export const clearStoredWorkspaceSegmentEditorTemporaryStateExcept = (
  email: string | null | undefined,
  keepProjectIds: readonly (number | null | undefined)[] = [],
) => {
  if (typeof window === "undefined") {
    return [];
  }

  const normalizedEmail = normalizeWorkspaceSegmentEditorStorageEmail(email);
  if (!normalizedEmail) {
    return [];
  }

  const keptProjectIds = new Set(
    keepProjectIds
      .map(getPositiveWorkspaceMediaAssetId)
      .filter((projectId): projectId is number => projectId !== null),
  );
  const clearedProjectIds = new Set<number>();
  const clearStoragePrefix = (storageKeyPrefix: string) => {
    readWorkspaceSegmentEditorStorageEntries(storageKeyPrefix).forEach((entry) => {
      const projectId = getPositiveWorkspaceMediaAssetId(entry.storageKey.slice(storageKeyPrefix.length));
      if (!projectId) {
        removeWorkspaceSegmentEditorStorageValueFrom(entry.storageName, entry.storageKey);
        return;
      }

      if (keptProjectIds.has(projectId)) {
        return;
      }

      removeWorkspaceSegmentEditorStorageValueFrom(entry.storageName, entry.storageKey);
      clearedProjectIds.add(projectId);
    });
  };

  clearStoragePrefix(`${WORKSPACE_SEGMENT_EDITOR_DRAFT_STORAGE_KEY_PREFIX}${normalizedEmail}:`);
  clearStoragePrefix(`${WORKSPACE_SEGMENT_EDITOR_EXPLICIT_STRUCTURE_STORAGE_KEY_PREFIX}${normalizedEmail}:`);

  const nextAiPhotoJobs = readStoredWorkspaceSegmentAiPhotoJobs(normalizedEmail).filter((job) => {
    const shouldKeep = keptProjectIds.has(job.projectId);
    if (!shouldKeep) {
      clearedProjectIds.add(job.projectId);
    }
    return shouldKeep;
  });
  writeStoredWorkspaceSegmentAiPhotoJobs(normalizedEmail, nextAiPhotoJobs);

  const nextPhotoAnimationJobs = readStoredWorkspaceSegmentPhotoAnimationJobs(normalizedEmail).filter((job) => {
    const shouldKeep = keptProjectIds.has(job.projectId);
    if (!shouldKeep) {
      clearedProjectIds.add(job.projectId);
    }
    return shouldKeep;
  });
  writeStoredWorkspaceSegmentPhotoAnimationJobs(normalizedEmail, nextPhotoAnimationJobs);

  const nextTalkingPhotoJobs = readStoredWorkspaceSegmentTalkingPhotoJobs(normalizedEmail).filter((job) => {
    const shouldKeep = keptProjectIds.has(job.projectId);
    if (!shouldKeep) {
      clearedProjectIds.add(job.projectId);
    }
    return shouldKeep;
  });
  writeStoredWorkspaceSegmentTalkingPhotoJobs(normalizedEmail, nextTalkingPhotoJobs);

  return Array.from(clearedProjectIds).sort((left, right) => left - right);
};

const moveArrayItemToInsertIndex = <T,>(items: T[], fromIndex: number, insertIndex: number) => {
  if (fromIndex < 0 || fromIndex >= items.length) {
    return items;
  }

  const boundedInsertIndex = Math.max(0, Math.min(insertIndex, items.length));
  const adjustedInsertIndex = boundedInsertIndex > fromIndex ? boundedInsertIndex - 1 : boundedInsertIndex;
  if (adjustedInsertIndex === fromIndex) {
    return items;
  }

  const nextItems = [...items];
  const [movedItem] = nextItems.splice(fromIndex, 1);
  if (typeof movedItem === "undefined") {
    return items;
  }

  nextItems.splice(adjustedInsertIndex, 0, movedItem);
  return nextItems;
};

const getVisibleInsertIndexForDraggedItem = (
  itemCount: number,
  draggedIndex: number | null,
  insertIndex: number | null,
) => {
  if (draggedIndex === null || insertIndex === null || draggedIndex < 0 || draggedIndex >= itemCount) {
    return null;
  }

  const boundedInsertIndex = Math.max(0, Math.min(insertIndex, itemCount));
  const adjustedInsertIndex = boundedInsertIndex > draggedIndex ? boundedInsertIndex - 1 : boundedInsertIndex;
  return adjustedInsertIndex === draggedIndex ? null : boundedInsertIndex;
};

export const resolveWorkspaceSegmentThumbFinalInsertIndex = (
  isDragActive: boolean,
  previewInsertIndex: number | null,
  pointerInsertIndex: number | null,
) => (isDragActive ? previewInsertIndex ?? pointerInsertIndex : null);

const reorderWorkspaceSegmentEditorSegmentsByIndex = (
  segments: WorkspaceSegmentEditorDraftSegment[],
  orderedSegmentIndices: number[],
) => {
  if (segments.length !== orderedSegmentIndices.length) {
    return segments;
  }

  const segmentsByIndex = new Map(segments.map((segment) => [segment.index, segment]));
  const nextSegments = orderedSegmentIndices
    .map((segmentIndex) => segmentsByIndex.get(segmentIndex))
    .filter((segment): segment is WorkspaceSegmentEditorDraftSegment => Boolean(segment));

  return nextSegments.length === segments.length ? nextSegments : segments;
};

const areWorkspaceSegmentEditorSegmentOrdersEqual = (
  left?: Pick<WorkspaceSegmentEditorDraftSession, "segments"> | null,
  right?: Pick<WorkspaceSegmentEditorDraftSession, "segments"> | null,
) => {
  if (!left || !right || left.segments.length !== right.segments.length) {
    return false;
  }

  return left.segments.every((segment, index) => segment.index === right.segments[index]?.index);
};

type WorkspaceSegmentEditorStructureSnapshot = Pick<WorkspaceSegmentEditorDraftSession, "segments">;

const normalizeWorkspaceSegmentEditorStructureBaselines = (
  baselineOrBaselines?:
    | WorkspaceSegmentEditorStructureSnapshot
    | readonly (WorkspaceSegmentEditorStructureSnapshot | null | undefined)[]
    | null,
) => {
  if (!baselineOrBaselines) {
    return [];
  }

  return (Array.isArray(baselineOrBaselines) ? baselineOrBaselines : [baselineOrBaselines]).filter(
    (baseline): baseline is WorkspaceSegmentEditorStructureSnapshot => Boolean(baseline),
  );
};

const getWorkspaceSegmentEditorBaselineSegmentIndexes = (
  baselineOrBaselines?:
    | WorkspaceSegmentEditorStructureSnapshot
    | readonly (WorkspaceSegmentEditorStructureSnapshot | null | undefined)[]
    | null,
) =>
  Array.from(
    new Set(
      normalizeWorkspaceSegmentEditorStructureBaselines(baselineOrBaselines).flatMap((baseline) =>
        baseline.segments.map((segment) => segment.index),
      ),
    ),
  );

const hasWorkspaceSegmentEditorNonCanonicalSourceOrder = (draft: WorkspaceSegmentEditorStructureSnapshot) =>
  draft.segments.some((segment, index) => segment.index !== index);

export const shouldRecoverWorkspaceSegmentEditorExplicitStructureChange = (
  draft?: WorkspaceSegmentEditorStructureSnapshot | null,
  baselineOrBaselines?:
    | WorkspaceSegmentEditorStructureSnapshot
    | readonly (WorkspaceSegmentEditorStructureSnapshot | null | undefined)[]
    | null,
) => {
  if (!draft) {
    return false;
  }

  if (hasWorkspaceSegmentEditorNonCanonicalSourceOrder(draft)) {
    return true;
  }

  const baselines = normalizeWorkspaceSegmentEditorStructureBaselines(baselineOrBaselines);
  if (!baselines.length) {
    return false;
  }

  return baselines.some((baseline) => {
    const baselineSegmentIndexes = new Set(baseline.segments.map((segment) => segment.index));
    return draft.segments.some((segment) => !baselineSegmentIndexes.has(segment.index));
  });
};

export const shouldAllowWorkspaceSegmentEditorStructureChange = (
  draft?: WorkspaceSegmentEditorStructureSnapshot | null,
  baselineOrBaselines?:
    | WorkspaceSegmentEditorStructureSnapshot
    | readonly (WorkspaceSegmentEditorStructureSnapshot | null | undefined)[]
    | null,
) => {
  if (!draft) {
    return false;
  }

  return (
    normalizeWorkspaceSegmentEditorStructureBaselines(baselineOrBaselines).some(
      (baseline) => !areWorkspaceSegmentEditorSegmentOrdersEqual(draft, baseline),
    ) || hasWorkspaceSegmentEditorNonCanonicalSourceOrder(draft)
  );
};

export const resolveWorkspaceSegmentEditorStructureChangePermission = (options: {
  baselineOrBaselines?:
    | WorkspaceSegmentEditorStructureSnapshot
    | readonly (WorkspaceSegmentEditorStructureSnapshot | null | undefined)[]
    | null;
  draft?: WorkspaceSegmentEditorStructureSnapshot | null;
  isExplicitStructureChange?: boolean;
}) => {
  const hasStructureChange = shouldAllowWorkspaceSegmentEditorStructureChange(
    options.draft,
    options.baselineOrBaselines,
  );
  const isExplicitStructureChange = Boolean(options.isExplicitStructureChange);

  return {
    allowStructureChange: hasStructureChange && isExplicitStructureChange,
    hasStructureChange,
    shouldBlockImplicitStructureChange: hasStructureChange && !isExplicitStructureChange,
  };
};

export const doesWorkspaceSegmentEditorPayloadMatchSessionStructure = (
  session?: WorkspaceSegmentEditorStructureSnapshot | null,
  payload?: Pick<WorkspaceSegmentEditorPayload, "segments"> | null,
) => {
  if (!session || !payload || session.segments.length !== payload.segments.length) {
    return false;
  }

  return session.segments.every((segment, index) => segment.index === payload.segments[index]?.index);
};

const getWorkspaceSegmentEditorDisplayNumber = (
  segments: WorkspaceSegmentEditorDraftSegment[],
  segmentIndex: number,
) => {
  const arrayIndex = segments.findIndex((segment) => segment.index === segmentIndex);
  return (arrayIndex >= 0 ? arrayIndex : segmentIndex) + 1;
};

const normalizeLegacyWorkspaceSegmentEditorDraftSession = (
  session: WorkspaceSegmentEditorDraftSession,
): WorkspaceSegmentEditorDraftSession => {
  let hasChanges = false;
  const fallbackLanguage = getWorkspaceSegmentEditorSessionLanguage(session);

  const segments = session.segments.map((segment) => {
    const normalizedSegment = normalizeWorkspaceSegmentEditorSegmentUrls(segment);
    const normalizedOriginalText =
      typeof segment.originalText === "string" && segment.originalText.trim() ? segment.originalText : segment.text;
    const normalizedVideoAction: WorkspaceSegmentEditorVideoAction =
      segment.videoAction === "ai" ||
      segment.videoAction === "ai_photo" ||
      segment.videoAction === "custom" ||
      segment.videoAction === "image_edit" ||
      segment.videoAction === "talking_photo" ||
      segment.videoAction === "photo_animation"
        ? segment.videoAction
        : "original";
    const normalizedAiPhotoPrompt = typeof segment.aiPhotoPrompt === "string" ? segment.aiPhotoPrompt : "";
    const normalizedAiPhotoGeneratedFromPrompt =
      typeof segment.aiPhotoGeneratedFromPrompt === "string" && segment.aiPhotoGeneratedFromPrompt.trim()
        ? segment.aiPhotoGeneratedFromPrompt
        : null;
    const normalizedAiPhotoPromptInitialized =
      Boolean(segment.aiPhotoPromptInitialized) ||
      Boolean(normalizedAiPhotoPrompt) ||
      Boolean(normalizedAiPhotoGeneratedFromPrompt);
    const normalizedAiVideoPrompt = typeof segment.aiVideoPrompt === "string" ? segment.aiVideoPrompt : "";
    const normalizedAiVideoGeneratedFromPrompt =
      typeof segment.aiVideoGeneratedFromPrompt === "string" && segment.aiVideoGeneratedFromPrompt.trim()
        ? segment.aiVideoGeneratedFromPrompt
        : null;
    const normalizedAiVideoGeneratedMode =
      segment.aiVideoGeneratedMode === "photo_animation" ||
      segment.aiVideoGeneratedMode === "talking_photo" ||
      segment.aiVideoGeneratedMode === "ai_video"
        ? segment.aiVideoGeneratedMode
        : null;
    const normalizedAiVideoPromptInitialized =
      Boolean(segment.aiVideoPromptInitialized) ||
      Boolean(normalizedAiVideoPrompt) ||
      Boolean(normalizedAiVideoGeneratedFromPrompt);
    const normalizedImageEditPrompt = typeof segment.imageEditPrompt === "string" ? segment.imageEditPrompt : "";
    const normalizedImageEditGeneratedFromPrompt =
      typeof segment.imageEditGeneratedFromPrompt === "string" && segment.imageEditGeneratedFromPrompt.trim()
        ? segment.imageEditGeneratedFromPrompt
        : null;
    const normalizedImageEditPromptInitialized =
      Boolean(segment.imageEditPromptInitialized) ||
      Boolean(normalizedImageEditPrompt) ||
      Boolean(normalizedImageEditGeneratedFromPrompt);
    const normalizedSceneSoundAsset =
      cloneStudioCustomVideoFile(segment.sceneSoundAsset) ??
      createWorkspaceSegmentSceneSoundAsset(normalizedSegment, normalizedSegment.index);
    const normalizedVoiceoverAsset =
      cloneStudioCustomVideoFile(segment.voiceoverAsset) ??
      createWorkspaceSegmentVoiceoverAsset(normalizedSegment, normalizedSegment.index);
    const normalizedVoiceoverTextHash =
      typeof segment.voiceoverTextHash === "string" && segment.voiceoverTextHash.trim()
        ? segment.voiceoverTextHash
        : normalizedVoiceoverAsset
          ? getWorkspaceSegmentVoiceoverTextHash(segment.text)
          : null;
    const normalizedVoiceoverVoiceType =
      typeof segment.voiceoverVoiceType === "string" && segment.voiceoverVoiceType.trim()
        ? segment.voiceoverVoiceType
        : normalizedVoiceoverAsset
          ? getWorkspaceSegmentVoiceOverrideId(segment) ?? normalizeWorkspaceSegmentEditorSetting(session.voiceType) ?? null
          : null;
    const normalizedVoiceoverLanguage =
      typeof segment.voiceoverLanguage === "string" && segment.voiceoverLanguage.trim()
        ? segment.voiceoverLanguage
        : normalizedVoiceoverAsset
          ? getWorkspaceSegmentEditorSessionLanguage(session)
          : null;
    const normalizedSceneSoundPrompt = typeof segment.sceneSoundPrompt === "string" ? segment.sceneSoundPrompt : "";
    const normalizedSceneSoundGeneratedFromPrompt =
      typeof segment.sceneSoundGeneratedFromPrompt === "string" && segment.sceneSoundGeneratedFromPrompt.trim()
        ? segment.sceneSoundGeneratedFromPrompt
        : null;
    const normalizedSceneSoundPromptInitialized =
      Boolean(segment.sceneSoundPromptInitialized) ||
      Boolean(normalizedSceneSoundPrompt) ||
      Boolean(normalizedSceneSoundGeneratedFromPrompt) ||
      Boolean(normalizedSceneSoundAsset);
    const normalizedSubtitleColor = getWorkspaceSegmentSubtitleColorOverrideId(segment);
    const normalizedSubtitleStyle = getWorkspaceSegmentSubtitleStyleOverrideId(segment);
    const normalizedSubtitleType = getWorkspaceSegmentSubtitleTypeOverrideId(segment);
    const normalizedVoiceType = getWorkspaceSegmentVoiceOverrideId(segment);
    const normalizedMediaType = normalizeWorkspaceSegmentMediaType(segment.mediaType);
    const normalizedDurationMode = normalizeWorkspaceSegmentDurationMode(segment.durationMode);
    const normalizedManualDurationSeconds = normalizeWorkspaceSegmentManualDurationSeconds(segment.manualDurationSeconds);
    const normalizedDurationExtensionSourceDurationSeconds =
      getWorkspaceSegmentStoredDurationExtensionSourceDurationSeconds(segment);
    const normalizedTextByLanguage = cloneWorkspaceSegmentEditorLocalizedTextMap(
      segment.textByLanguage,
      segment.text,
      fallbackLanguage,
    );
    const normalizedOriginalTextByLanguage = cloneWorkspaceSegmentEditorLocalizedTextMap(
      segment.originalTextByLanguage,
      normalizedOriginalText,
      fallbackLanguage,
    );
    const hasUrlChanges =
      normalizedSegment.currentExternalPlaybackUrl !== segment.currentExternalPlaybackUrl ||
      normalizedSegment.currentExternalPreviewUrl !== segment.currentExternalPreviewUrl ||
      normalizedSegment.currentPlaybackUrl !== segment.currentPlaybackUrl ||
      normalizedSegment.currentPosterUrl !== segment.currentPosterUrl ||
      normalizedSegment.currentPreviewUrl !== segment.currentPreviewUrl ||
      normalizedSegment.currentSourceKind !== segment.currentSourceKind ||
      normalizedSegment.originalExternalPlaybackUrl !== segment.originalExternalPlaybackUrl ||
      normalizedSegment.originalExternalPreviewUrl !== segment.originalExternalPreviewUrl ||
      normalizedSegment.originalPlaybackUrl !== segment.originalPlaybackUrl ||
      normalizedSegment.originalPosterUrl !== segment.originalPosterUrl ||
      normalizedSegment.originalPreviewUrl !== segment.originalPreviewUrl ||
      normalizedSegment.originalSourceKind !== segment.originalSourceKind;
    const hasOriginalTextChanges = normalizedOriginalText !== segment.originalText;
    const hasLocalizedTextChanges =
      !areWorkspaceSegmentEditorLocalizedTextMapsEqual(normalizedTextByLanguage, segment.textByLanguage) ||
      !areWorkspaceSegmentEditorLocalizedTextMapsEqual(normalizedOriginalTextByLanguage, segment.originalTextByLanguage);
    const hasAiPhotoChanges =
      normalizedAiPhotoPrompt !== segment.aiPhotoPrompt ||
      normalizedAiPhotoGeneratedFromPrompt !== segment.aiPhotoGeneratedFromPrompt ||
      normalizedAiPhotoPromptInitialized !== segment.aiPhotoPromptInitialized ||
      normalizedAiVideoPrompt !== segment.aiVideoPrompt ||
      normalizedAiVideoGeneratedFromPrompt !== segment.aiVideoGeneratedFromPrompt ||
      normalizedAiVideoGeneratedMode !== segment.aiVideoGeneratedMode ||
      normalizedAiVideoPromptInitialized !== segment.aiVideoPromptInitialized ||
      normalizedImageEditPrompt !== segment.imageEditPrompt ||
      normalizedImageEditGeneratedFromPrompt !== segment.imageEditGeneratedFromPrompt ||
      normalizedImageEditPromptInitialized !== segment.imageEditPromptInitialized ||
      Boolean(normalizedSceneSoundAsset) !== Boolean(segment.sceneSoundAsset) ||
      normalizedSceneSoundPrompt !== segment.sceneSoundPrompt ||
      normalizedSceneSoundGeneratedFromPrompt !== segment.sceneSoundGeneratedFromPrompt ||
      normalizedSceneSoundPromptInitialized !== segment.sceneSoundPromptInitialized ||
      Boolean(normalizedVoiceoverAsset) !== Boolean(segment.voiceoverAsset) ||
      normalizedVoiceoverTextHash !== segment.voiceoverTextHash ||
      normalizedVoiceoverVoiceType !== segment.voiceoverVoiceType ||
      normalizedVoiceoverLanguage !== segment.voiceoverLanguage ||
      normalizedSubtitleColor !== (segment.subtitleColor ?? null) ||
      normalizedSubtitleStyle !== (segment.subtitleStyle ?? null) ||
      normalizedSubtitleType !== (segment.subtitleType ?? null) ||
      normalizedVoiceType !== getWorkspaceSegmentVoiceOverrideId(segment) ||
      normalizedVideoAction !== segment.videoAction ||
      normalizedMediaType !== segment.mediaType ||
          normalizedDurationMode !== segment.durationMode ||
          !areWorkspaceSegmentDurationValuesEqual(
            normalizedManualDurationSeconds,
            normalizeWorkspaceSegmentManualDurationSeconds(segment.manualDurationSeconds),
          ) ||
          !areWorkspaceSegmentDurationValuesEqual(
            normalizedDurationExtensionSourceDurationSeconds,
            getWorkspaceSegmentStoredDurationExtensionSourceDurationSeconds(segment),
          );

    if (
      segment.customVideo ||
      segment.aiPhotoAsset ||
      segment.aiVideoAsset ||
      segment.imageEditAsset ||
      segment.photoAnimationSourceAsset ||
      segment.sceneSoundAsset ||
      normalizedSceneSoundAsset ||
      normalizedVideoAction === "original" ||
      normalizedVideoAction === "ai" ||
      normalizedVideoAction === "custom" ||
      normalizedVideoAction === "ai_photo" ||
      normalizedVideoAction === "image_edit" ||
      normalizedVideoAction === "talking_photo" ||
      normalizedVideoAction === "photo_animation"
    ) {
      if (!hasUrlChanges && !hasOriginalTextChanges && !hasLocalizedTextChanges && !hasAiPhotoChanges) {
        return segment;
      }

      hasChanges = true;
      return {
        ...normalizedSegment,
        aiPhotoAsset: cloneStudioCustomVideoFile(segment.aiPhotoAsset),
        aiPhotoGeneratedFromPrompt: normalizedAiPhotoGeneratedFromPrompt,
        aiPhotoPrompt: normalizedAiPhotoPrompt,
        aiPhotoPromptInitialized: normalizedAiPhotoPromptInitialized,
        aiVideoAsset: cloneStudioCustomVideoFile(segment.aiVideoAsset),
        aiVideoGeneratedMode: normalizedAiVideoGeneratedMode,
        aiVideoGeneratedFromPrompt: normalizedAiVideoGeneratedFromPrompt,
        aiVideoPrompt: normalizedAiVideoPrompt,
        aiVideoPromptInitialized: normalizedAiVideoPromptInitialized,
        customVideo: cloneStudioCustomVideoFile(segment.customVideo),
        durationExtensionSourceDurationSeconds: normalizedDurationExtensionSourceDurationSeconds,
        durationMode: normalizedDurationMode,
        imageEditAsset: cloneStudioCustomVideoFile(segment.imageEditAsset),
        imageEditGeneratedFromPrompt: normalizedImageEditGeneratedFromPrompt,
        imageEditPrompt: normalizedImageEditPrompt,
        imageEditPromptInitialized: normalizedImageEditPromptInitialized,
        manualDurationSeconds: normalizedManualDurationSeconds,
        mediaType: normalizedMediaType,
        originalText: normalizedOriginalText,
        originalTextByLanguage: normalizedOriginalTextByLanguage,
        photoAnimationSourceAsset: cloneStudioCustomVideoFile(segment.photoAnimationSourceAsset),
        sceneSoundAsset: normalizedSceneSoundAsset,
        sceneSoundGeneratedFromPrompt: normalizedSceneSoundGeneratedFromPrompt,
        sceneSoundPrompt: normalizedSceneSoundPrompt,
        sceneSoundPromptInitialized: normalizedSceneSoundPromptInitialized,
        subtitleColor: normalizedSubtitleColor,
        subtitleStyle: normalizedSubtitleStyle,
        subtitleType: normalizedSubtitleType,
        textByLanguage: normalizedTextByLanguage,
        voiceoverAsset: normalizedVoiceoverAsset,
        voiceoverLanguage: normalizedVoiceoverLanguage,
        voiceoverTextHash: normalizedVoiceoverTextHash,
        voiceoverVoiceType: normalizedVoiceoverVoiceType,
        videoAction: normalizedVideoAction,
        voiceType: normalizedVoiceType,
        visualReset: Boolean(segment.visualReset),
      };
    }

    hasChanges = true;
    return {
      ...normalizedSegment,
      aiPhotoAsset: null,
      aiPhotoGeneratedFromPrompt: normalizedAiPhotoGeneratedFromPrompt,
      aiPhotoPrompt: normalizedAiPhotoPrompt,
      aiPhotoPromptInitialized: normalizedAiPhotoPromptInitialized,
      aiVideoAsset: null,
      aiVideoGeneratedMode: normalizedAiVideoGeneratedMode,
      aiVideoGeneratedFromPrompt: normalizedAiVideoGeneratedFromPrompt,
      aiVideoPrompt: normalizedAiVideoPrompt,
      aiVideoPromptInitialized: normalizedAiVideoPromptInitialized,
      durationExtensionSourceDurationSeconds: normalizedDurationExtensionSourceDurationSeconds,
      durationMode: normalizedDurationMode,
      imageEditAsset: null,
      imageEditGeneratedFromPrompt: normalizedImageEditGeneratedFromPrompt,
      imageEditPrompt: normalizedImageEditPrompt,
      imageEditPromptInitialized: normalizedImageEditPromptInitialized,
      manualDurationSeconds: normalizedManualDurationSeconds,
      mediaType: normalizedMediaType,
      originalText: normalizedOriginalText,
      originalTextByLanguage: normalizedOriginalTextByLanguage,
      photoAnimationSourceAsset: null,
      sceneSoundAsset: normalizedSceneSoundAsset,
      sceneSoundGeneratedFromPrompt: normalizedSceneSoundGeneratedFromPrompt,
      sceneSoundPrompt: normalizedSceneSoundPrompt,
      sceneSoundPromptInitialized: normalizedSceneSoundPromptInitialized,
      subtitleColor: normalizedSubtitleColor,
      subtitleStyle: normalizedSubtitleStyle,
      subtitleType: normalizedSubtitleType,
      textByLanguage: normalizedTextByLanguage,
      voiceoverAsset: normalizedVoiceoverAsset,
      voiceoverLanguage: normalizedVoiceoverLanguage,
      voiceoverTextHash: normalizedVoiceoverTextHash,
      voiceoverVoiceType: normalizedVoiceoverVoiceType,
      videoAction: "original" as const,
      voiceType: normalizedVoiceType,
      visualReset: Boolean(segment.visualReset),
    };
  });

  const visualResetSegments = segments.map((segment) => {
    if (!segment.visualReset) {
      return segment;
    }

    hasChanges = true;
    return resetWorkspaceSegmentDraftVisualToOriginal(segment, session.projectId);
  });
  const normalizedSegments = rebuildWorkspaceSegmentEditorDraftTimeline(visualResetSegments, session);

  return hasChanges || normalizedSegments !== visualResetSegments
    ? {
        ...session,
        segments: normalizedSegments,
      }
    : session;
};

type WorkspaceSegmentEditorUploadFile = {
  fieldName: string;
  file: File;
  fileName: string;
};

/** If the user opened a generation mode but never produced an asset, export uses the segment's original media. */
const resolveWorkspaceSegmentExportVideoAction = (
  segment: WorkspaceSegmentEditorDraftSegment,
): WorkspaceSegmentEditorVideoAction => {
  const { videoAction } = segment;
  if (videoAction === "ai" && !hasWorkspaceSegmentDisplayAiVideoAsset(segment, "ai_video")) {
    return "original";
  }
  if (videoAction === "photo_animation" && !hasWorkspaceSegmentDisplayAiVideoAsset(segment, "photo_animation")) {
    return "original";
  }
  if (videoAction === "talking_photo" && !hasWorkspaceSegmentDisplayAiVideoAsset(segment, "talking_photo")) {
    return "original";
  }
  if (videoAction === "ai_photo" && !isWorkspaceSegmentAiPhotoReady(segment)) {
    return "original";
  }
  if (videoAction === "image_edit" && !isWorkspaceSegmentImageEditReady(segment)) {
    return "original";
  }
  if (videoAction === "custom" && !segment.customVideo) {
    return "original";
  }
  return videoAction;
};

const isWorkspaceSegmentCustomVisualSameAsOriginal = (
  segment: WorkspaceSegmentEditorDraftSegment,
  asset: StudioCustomVideoFile | null | undefined,
) => {
  const assetIdentity = getStudioCustomVideoFileIdentityKey(asset);
  if (!assetIdentity) {
    return false;
  }

  return getWorkspaceSegmentOriginalVisualIdentityKey(segment) === assetIdentity;
};

const isWorkspaceSegmentCustomVisualSameAsCurrent = (
  segment: WorkspaceSegmentEditorDraftSegment,
  asset: StudioCustomVideoFile | null | undefined,
) => {
  const assetIdentity = getStudioCustomVideoFileIdentityKey(asset);
  if (!assetIdentity) {
    return false;
  }

  return getWorkspaceSegmentCurrentVisualIdentityKey(segment) === assetIdentity;
};

export const buildWorkspaceSegmentEditorPayload = async (
  session: WorkspaceSegmentEditorDraftSession,
  options: {
    allowStructureChange?: boolean;
    language: StudioLanguage;
    persistedSegmentIndexes?: readonly number[];
  },
): Promise<{ payload: WorkspaceSegmentEditorPayload; uploads: WorkspaceSegmentEditorUploadFile[] }> => {
  const segments: WorkspaceSegmentEditorPayloadSegment[] = [];
  const uploads: WorkspaceSegmentEditorUploadFile[] = [];
  const normalizedSegments = rebuildWorkspaceSegmentEditorDraftTimeline(session.segments, session);
  let timelineCursor = 0;

  for (const segment of normalizedSegments) {
    const mediaUploadScope = resolveWorkspaceSegmentEditorMediaUploadScope(session, segment, {
      allowStructureChange: options.allowStructureChange,
      persistedSegmentIndexes: options.persistedSegmentIndexes,
    });
    const exportAction = resolveWorkspaceSegmentExportVideoAction(segment);
    const selectedAiVideoAsset =
      exportAction === "ai"
        ? hasWorkspaceSegmentDisplayAiVideoAsset(segment, "ai_video")
          ? segment.aiVideoAsset
          : null
        : exportAction === "photo_animation"
          ? hasWorkspaceSegmentDisplayAiVideoAsset(segment, "photo_animation")
            ? segment.aiVideoAsset
            : null
        : exportAction === "talking_photo"
          ? hasWorkspaceSegmentDisplayAiVideoAsset(segment, "talking_photo")
            ? segment.aiVideoAsset
            : null
          : null;
    const customVisualAsset =
      exportAction === "custom"
        ? segment.customVideo
        : exportAction === "image_edit"
          ? segment.imageEditAsset
          : exportAction === "ai_photo"
            ? segment.aiPhotoAsset
            : selectedAiVideoAsset
              ? selectedAiVideoAsset
              : null;
    const isTalkingPhotoExport = exportAction === "talking_photo" && Boolean(selectedAiVideoAsset);
    const payloadVideoAction: WorkspaceSegmentEditorPayloadVideoAction =
      exportAction === "ai_photo" || exportAction === "image_edit" || Boolean(selectedAiVideoAsset)
        ? "custom"
        : exportAction === "photo_animation" || exportAction === "talking_photo"
          ? "original"
          : exportAction;
    let customVideoFileDataUrl: string | undefined;
    let customVideoAssetId: number | undefined;
    let customVideoFileUploadKey: string | undefined;
    let customVideoRemoteUrl: string | undefined;
    const sceneSoundAssetId = getWorkspaceSegmentSceneSoundAssetId(segment.sceneSoundAsset) ?? undefined;
    const payloadVideoActionForSegment: WorkspaceSegmentEditorPayloadVideoAction =
      payloadVideoAction === "custom" &&
      isWorkspaceSegmentCustomVisualSameAsCurrent(segment, customVisualAsset) &&
      isWorkspaceSegmentCurrentVisualDifferentFromOriginal(segment)
        ? "original"
        : payloadVideoAction;

    if (payloadVideoActionForSegment === "custom") {
      if (isWorkspaceSegmentCustomVisualSameAsOriginal(segment, customVisualAsset)) {
        throw new Error(
          `Визуал сегмента ${segment.index + 1} не обновился. Сгенерируйте ИИ фото ещё раз или обновите редактор.`,
        );
      }

      if (customVisualAsset?.assetId) {
        customVideoAssetId = customVisualAsset.assetId;
      } else if (customVisualAsset) {
        customVideoAssetId = (await ensureStudioUploadedAssetId(customVisualAsset, {
          fallbackFileName: customVisualAsset.fileName || `segment-visual-${segment.index + 1}.bin`,
          fallbackMimeType: customVisualAsset.mimeType,
          kind: "segment_source",
          language: options.language,
          mediaType: getWorkspaceSegmentCustomPreviewKind(customVisualAsset) === "image" ? "photo" : "video",
          projectId: mediaUploadScope.projectId,
          role: "segment_source",
          segmentIndex: mediaUploadScope.segmentIndex,
        })) ?? undefined;
      }

      if (!customVideoAssetId && typeof customVisualAsset?.remoteUrl === "string" && customVisualAsset.remoteUrl.trim()) {
        customVideoRemoteUrl = customVisualAsset.remoteUrl.trim();
      } else {
        customVideoFileDataUrl = customVideoAssetId ? undefined : await resolveStudioCustomAssetDataUrl(customVisualAsset);
      }
    }

    const durationMode =
      isTalkingPhotoExport
        ? "manual"
        : normalizeWorkspaceSegmentDurationMode(segment.durationMode);
    const manualDurationSeconds = normalizeWorkspaceSegmentManualDurationSeconds(segment.manualDurationSeconds);
    const startTime = timelineCursor;
    const sourceStartTime = getWorkspaceSegmentEditorDisplayStartTime(segment);
    const timelineDuration = getWorkspaceSegmentEditorDisplayEndTime(segment) - sourceStartTime;
    const normalizedTimelineDuration = normalizeWorkspaceSegmentManualDurationSeconds(timelineDuration);
    const normalizedSegmentDuration = normalizeWorkspaceSegmentManualDurationSeconds(segment.duration);
    const manualDurationCandidates = [manualDurationSeconds, normalizedTimelineDuration, normalizedSegmentDuration].filter(
      (value): value is number => value !== null,
    );
    const resolvedManualDurationSeconds =
      durationMode === "manual" && manualDurationCandidates.length > 0
          ? Math.max(...manualDurationCandidates)
          : null;
    const rawDuration =
      durationMode === "manual" && resolvedManualDurationSeconds !== null
        ? resolvedManualDurationSeconds
        : normalizedSegmentDuration ?? normalizedTimelineDuration ?? undefined;
    const duration = typeof rawDuration === "number" ? roundWorkspaceSegmentTimelineSeconds(rawDuration) : undefined;
    const endTime = typeof duration === "number" ? roundWorkspaceSegmentTimelineSeconds(startTime + duration) : segment.endTime;
    const roundedManualDurationSeconds =
      durationMode === "manual" && resolvedManualDurationSeconds !== null
        ? roundWorkspaceSegmentTimelineSeconds(resolvedManualDurationSeconds)
        : null;
    const talkingPhotoMediaDurationSeconds = isTalkingPhotoExport
      ? getStudioCustomVideoFileDurationSeconds(selectedAiVideoAsset)
      : null;
    if (
      isTalkingPhotoExport &&
      typeof duration === "number" &&
      talkingPhotoMediaDurationSeconds !== null &&
      talkingPhotoMediaDurationSeconds > duration + WORKSPACE_SEGMENT_TALKING_PHOTO_DURATION_OVERFLOW_TOLERANCE_SECONDS
    ) {
      throw new Error(
        `Говорящий персонаж сегмента ${segment.index + 1} длиннее таймлайна сцены. Увеличьте длительность сегмента и попробуйте экспорт снова.`,
      );
    }
    const roundedStartTime = roundWorkspaceSegmentTimelineSeconds(startTime);
    if (typeof duration === "number") {
      timelineCursor = endTime;
    }
    const segmentVoiceType = isTalkingPhotoExport ? "none" : getWorkspaceSegmentVoiceOverrideId(segment);
    const segmentHasVoice =
      segmentVoiceType === "none"
        ? false
        : normalizeWorkspaceSegmentEditorSetting(session.voiceType) !== "none" || Boolean(segmentVoiceType);
    const segmentSubtitleTypeOverride = getWorkspaceSegmentSubtitleTypeOverrideId(segment);
    const segmentSubtitleStyle = segmentHasVoice ? getWorkspaceSegmentSubtitleStyleOverrideId(segment) : null;
    const segmentSubtitleColor = segmentHasVoice ? getWorkspaceSegmentSubtitleColorOverrideId(segment) : null;
    const segmentEffectiveSubtitleSettings = getWorkspaceSegmentEffectiveSubtitleSettings(session, segment, {
      subtitleColorId: fallbackStudioSubtitleColorOption.id,
      subtitleStyleId: fallbackStudioSubtitleStyleOption.id,
    });
    const segmentSubtitleType = segmentHasVoice
      ? segmentSubtitleTypeOverride ??
        (!segmentEffectiveSubtitleSettings.globalEnabled &&
        segmentEffectiveSubtitleSettings.isEnabled &&
        (segmentSubtitleStyle || segmentSubtitleColor)
          ? "default"
          : null)
      : "none";
    const voiceoverAssetId = isWorkspaceSegmentVoiceoverAssetFresh(segment, session)
      ? getWorkspaceSegmentCustomAssetId(segment.voiceoverAsset) ?? undefined
      : undefined;

    segments.push({
      customVideoAssetId,
      customVideoFileDataUrl,
      customVideoFileMimeType: payloadVideoActionForSegment === "custom" ? customVisualAsset?.mimeType : undefined,
      customVideoFileName: payloadVideoActionForSegment === "custom" ? customVisualAsset?.fileName : undefined,
      customVideoRemoteUrl,
      customVideoFileUploadKey,
      duration,
      durationExtensionSourceDurationSeconds: getWorkspaceSegmentStoredDurationExtensionSourceDurationSeconds(segment),
      durationMode,
      endTime,
      // Keep the original segment identity in `index`; array order carries the new sequence after reorder.
      index: segment.index,
      manualDurationSeconds: roundedManualDurationSeconds,
      resetVisual: Boolean(segment.visualReset),
      sceneSoundAssetId,
      startTime: roundedStartTime,
      ...(segmentSubtitleColor ? { subtitleColor: segmentSubtitleColor } : {}),
      ...(segmentSubtitleStyle ? { subtitleStyle: segmentSubtitleStyle } : {}),
      ...(segmentSubtitleType ? { subtitleType: segmentSubtitleType } : {}),
      text: segment.text,
      videoAction: payloadVideoActionForSegment,
      voiceoverAssetId,
      voiceType: segmentVoiceType,
    });
  }

  return {
    payload: {
      allowStructureChange: Boolean(options.allowStructureChange),
      projectId: session.projectId,
      segments,
    },
    uploads,
  };
};

const isWorkspaceSegmentEditorNotFoundError = (value: string) => {
  const normalized = value.trim().toLowerCase();
  return normalized === "not found" || normalized.includes("404");
};

const isWorkspaceSegmentEditorPreparingError = (value: string) => {
  const normalized = value.trim().toLowerCase();
  return (
    normalized.includes("пока") ||
    normalized.includes("not ready") ||
    normalized.includes("still being prepared") ||
    normalized.includes("project_not_ready") ||
    normalized.includes("does not have segment data") ||
    normalized.includes("segment data")
  );
};

const waitWorkspaceDelay = (ms: number) => new Promise((resolve) => window.setTimeout(resolve, ms));

const getWorkspaceSegmentExternalVideoFallbackUrls = (segment: WorkspaceSegmentEditorDraftSegment) =>
  getUniqueWorkspaceSegmentPreviewUrls([
    segment.currentExternalPlaybackUrl,
    segment.originalExternalPlaybackUrl,
    segment.currentExternalPreviewUrl,
    segment.originalExternalPreviewUrl,
  ]);

const getWorkspaceSegmentPersistedSourceKind = (segment: WorkspaceSegmentEditorDraftSegment): WorkspaceSegmentSourceKind =>
  [
    segment.currentSourceKind,
    segment.currentAsset?.sourceKind,
    segment.originalSourceKind,
    segment.originalAsset?.sourceKind,
  ]
    .map(normalizeWorkspaceSegmentSourceKind)
    .find((sourceKind) => sourceKind !== "unknown") ?? "unknown";

const getWorkspaceSegmentVisualResetPreviewUrl = (segment: WorkspaceSegmentEditorDraftSegment) => {
  if (!segment.visualReset) {
    return null;
  }

  if (isWorkspaceSegmentStaleUploadOriginalVisual(segment)) {
    return (
      segment.originalPreviewUrl ??
      segment.originalExternalPreviewUrl ??
      segment.originalPlaybackUrl ??
      segment.originalExternalPlaybackUrl ??
      null
    );
  }

  return (
    segment.originalPreviewUrl ??
    segment.originalExternalPreviewUrl ??
    segment.originalPlaybackUrl ??
    segment.originalExternalPlaybackUrl ??
    null
  );
};

const getWorkspaceSegmentVisualResetVideoUrl = (segment: WorkspaceSegmentEditorDraftSegment) => {
  if (!segment.visualReset) {
    return null;
  }

  if (isWorkspaceSegmentStaleUploadOriginalVisual(segment)) {
    return (
      segment.originalPlaybackUrl ??
      segment.originalExternalPlaybackUrl ??
      segment.originalPreviewUrl ??
      segment.originalExternalPreviewUrl ??
      null
    );
  }

  return (
    segment.originalPlaybackUrl ??
    segment.originalExternalPlaybackUrl ??
    segment.originalPreviewUrl ??
    segment.originalExternalPreviewUrl ??
    null
  );
};

export const getWorkspaceSegmentDraftPreviewUrl = (segment: WorkspaceSegmentEditorDraftSegment) => {
  if (segment.visualReset && !hasWorkspaceSegmentExplicitDraftVisual(segment)) {
    return getWorkspaceSegmentVisualResetPreviewUrl(segment);
  }

  if (shouldUseWorkspaceSegmentAiPhotoRenderedStillPreview(segment)) {
    return (
      getWorkspaceSegmentVideoAssetPosterUrl(segment) ??
      getWorkspaceSegmentPreferredStillPreviewUrl(segment) ??
      null
    );
  }

  const latestVisualAction = getWorkspaceSegmentLatestVisualAction(segment);
  const preferredStillPreviewUrl = getWorkspaceSegmentPreferredStillPreviewUrl(segment);
  const fallbackStillPreviewUrl =
    preferredStillPreviewUrl ??
    (segment.mediaType === "photo"
      ? null
      : segment.currentPreviewUrl ??
        segment.originalPreviewUrl ??
        segment.currentExternalPreviewUrl ??
        segment.originalExternalPreviewUrl);
  const fallbackPreviewUrl =
    fallbackStillPreviewUrl ??
    segment.currentPlaybackUrl ??
    segment.originalPlaybackUrl ??
    segment.currentExternalPlaybackUrl ??
    segment.originalExternalPlaybackUrl;

  if (latestVisualAction === "ai") {
    const displayGeneratedVideoUrl = getWorkspaceSegmentDisplayAiVideoAssetUrl(segment, "ai_video");
    return (
      (displayGeneratedVideoUrl ? getWorkspaceAiVideoPreferredPosterUrl(segment, segment.aiVideoAsset) : null) ??
      displayGeneratedVideoUrl ??
      fallbackStillPreviewUrl ??
      fallbackPreviewUrl
    );
  }

  if (latestVisualAction === "photo_animation") {
    const displayGeneratedVideoUrl = getWorkspaceSegmentDisplayAiVideoAssetUrl(segment, "photo_animation");
    const sourcePreviewUrl = getWorkspacePhotoAnimationSourcePosterUrl(segment);
    return (
      (displayGeneratedVideoUrl ? getWorkspacePhotoAnimationPreferredPosterUrl(segment, segment.aiVideoAsset) : null) ??
      displayGeneratedVideoUrl ??
      sourcePreviewUrl ??
      fallbackStillPreviewUrl ??
      fallbackPreviewUrl
    );
  }

  if (latestVisualAction === "talking_photo") {
    const displayGeneratedVideoUrl = getWorkspaceSegmentDisplayAiVideoAssetUrl(segment, "talking_photo");
    const sourcePreviewUrl = getWorkspacePhotoAnimationSourcePosterUrl(segment);
    return (
      (displayGeneratedVideoUrl ? getWorkspacePhotoAnimationPreferredPosterUrl(segment, segment.aiVideoAsset) : null) ??
      displayGeneratedVideoUrl ??
      sourcePreviewUrl ??
      fallbackStillPreviewUrl ??
      fallbackPreviewUrl
    );
  }

  if (segment.videoAction === "custom") {
    const customPreviewUrl = getStudioCustomAssetPreviewUrl(segment.customVideo);
    if (segment.customVideo?.source === "media-library") {
      if (getWorkspaceSegmentCustomPreviewKind(segment.customVideo) === "video") {
        return getStudioCustomAssetPosterUrl(segment.customVideo) ?? customPreviewUrl;
      }

      return customPreviewUrl;
    }

    if (getWorkspaceSegmentCustomPreviewKind(segment.customVideo) === "video") {
      return getStudioCustomAssetPosterUrl(segment.customVideo) ?? customPreviewUrl ?? fallbackPreviewUrl;
    }

    return customPreviewUrl ?? fallbackPreviewUrl;
  }

  if (segment.videoAction === "image_edit") {
    return (
      getStudioCustomAssetPreviewUrl(segment.imageEditAsset) ??
      getStudioCustomAssetPreviewUrl(getWorkspaceSegmentPendingImageEditSourceAsset(segment)) ??
      fallbackPreviewUrl
    );
  }

  if (segment.videoAction === "ai_photo") {
    return (
      getStudioCustomAssetPreviewUrl(segment.aiPhotoAsset) ??
      fallbackPreviewUrl
    );
  }

  if (segment.videoAction === "original") {
    if (isWorkspaceSegmentServerPhotoAnimationOverride(segment)) {
      return (
        getWorkspacePhotoAnimationSourcePosterUrl(segment) ??
        segment.currentPreviewUrl ??
        segment.currentExternalPreviewUrl ??
        segment.currentPlaybackUrl ??
        segment.currentExternalPlaybackUrl ??
        fallbackStillPreviewUrl ??
        fallbackPreviewUrl
      );
    }

    if (segment.mediaType === "video") {
      return (
        segment.originalPreviewUrl ??
        segment.originalPlaybackUrl ??
        segment.currentPreviewUrl ??
        segment.currentPlaybackUrl ??
        preferredStillPreviewUrl ??
        segment.originalExternalPreviewUrl ??
        segment.currentExternalPreviewUrl ??
        segment.originalExternalPlaybackUrl ??
        segment.currentExternalPlaybackUrl
      );
    }

    return (
      preferredStillPreviewUrl ??
      segment.originalPreviewUrl ??
      segment.originalExternalPreviewUrl ??
      segment.originalPlaybackUrl ??
      segment.originalExternalPlaybackUrl ??
      segment.currentPreviewUrl ??
      segment.currentExternalPreviewUrl ??
      segment.currentPlaybackUrl ??
      segment.currentExternalPlaybackUrl
    );
  }

  if (segment.mediaType === "photo") {
    return preferredStillPreviewUrl;
  }

  return (
    segment.currentPreviewUrl ??
    segment.currentPlaybackUrl ??
    preferredStillPreviewUrl ??
    segment.currentExternalPreviewUrl ??
    segment.currentExternalPlaybackUrl ??
    segment.originalPreviewUrl ??
    segment.originalPlaybackUrl ??
    segment.originalExternalPreviewUrl ??
    segment.originalExternalPlaybackUrl
  );
};

export const getWorkspaceSegmentDraftPosterUrl = (segment: WorkspaceSegmentEditorDraftSegment) => {
  if (segment.visualReset && !hasWorkspaceSegmentExplicitDraftVisual(segment)) {
    return getWorkspaceSegmentOriginalPosterUrl(segment);
  }

  const latestVisualAction = getWorkspaceSegmentLatestVisualAction(segment);

  if (latestVisualAction === "ai") {
    return (
      getWorkspaceAiVideoPreferredPosterUrl(segment, segment.aiVideoAsset) ??
      getWorkspaceSegmentCurrentPosterUrl(segment) ??
      getWorkspaceSegmentOriginalPosterUrl(segment)
    );
  }

  if (latestVisualAction === "photo_animation") {
    return (
      getWorkspacePhotoAnimationPreferredPosterUrl(segment, segment.aiVideoAsset) ??
      getWorkspacePhotoAnimationSourcePosterUrl(segment) ??
      getWorkspaceSegmentCurrentPosterUrl(segment) ??
      getWorkspaceSegmentOriginalPosterUrl(segment)
    );
  }

  if (latestVisualAction === "talking_photo") {
    return (
      getWorkspacePhotoAnimationPreferredPosterUrl(segment, segment.aiVideoAsset) ??
      getWorkspacePhotoAnimationSourcePosterUrl(segment) ??
      getWorkspaceSegmentCurrentPosterUrl(segment) ??
      getWorkspaceSegmentOriginalPosterUrl(segment)
    );
  }

  if (segment.videoAction === "custom" && getWorkspaceSegmentCustomPreviewKind(segment.customVideo) === "video") {
    return getStudioCustomAssetPosterUrl(segment.customVideo);
  }

  if (segment.videoAction === "original") {
    return isWorkspaceSegmentServerPhotoAnimationOverride(segment)
      ? getWorkspaceSegmentCurrentPosterUrl(segment)
      : getWorkspaceSegmentOriginalPosterUrl(segment);
  }

  return getWorkspaceSegmentCurrentPosterUrl(segment) ?? getWorkspaceSegmentOriginalPosterUrl(segment);
};

const getWorkspaceSegmentDraftFallbackPosterUrl = (segment: WorkspaceSegmentEditorDraftSegment) => {
  if (segment.visualReset && !hasWorkspaceSegmentExplicitDraftVisual(segment)) {
    return null;
  }

  const latestVisualAction = getWorkspaceSegmentLatestVisualAction(segment);

  if (latestVisualAction === "photo_animation" || latestVisualAction === "talking_photo") {
    return (
      getWorkspacePhotoAnimationSourcePosterUrl(segment) ??
      getWorkspaceSegmentCurrentPosterUrl(segment) ??
      getWorkspaceSegmentOriginalPosterUrl(segment) ??
      segment.currentExternalPreviewUrl ??
      segment.originalExternalPreviewUrl ??
      segment.currentPreviewUrl ??
      segment.originalPreviewUrl ??
      null
    );
  }

  if (segment.videoAction === "original" && segment.mediaType === "video") {
    if (isWorkspaceSegmentServerPhotoAnimationOverride(segment)) {
      return (
        getWorkspaceSegmentCurrentPosterUrl(segment) ??
        segment.currentExternalPreviewUrl ??
        segment.currentPreviewUrl ??
        null
      );
    }

    return (
      getWorkspaceSegmentOriginalPosterUrl(segment) ??
      segment.originalExternalPreviewUrl ??
      null
    );
  }

  if (segment.videoAction === "custom" && getWorkspaceSegmentCustomPreviewKind(segment.customVideo) === "video") {
    // A user-selected custom video must not inherit the previous segment still frame.
    // Otherwise the carousel keeps showing the old photo until playback starts.
    return null;
  }

  return null;
};

export const getWorkspaceSegmentDraftPreviewFallbackUrls = (
  segment: WorkspaceSegmentEditorDraftSegment,
  previewKind: WorkspaceSegmentPreviewKind,
) => {
  if (segment.visualReset && !hasWorkspaceSegmentExplicitDraftVisual(segment)) {
    return getUniqueWorkspaceSegmentPreviewUrls([
      segment.originalPlaybackUrl,
      segment.originalPreviewUrl,
      ...(isWorkspaceSegmentStaleUploadOriginalVisual(segment)
        ? []
        : [segment.originalExternalPlaybackUrl, segment.originalExternalPreviewUrl]),
    ]);
  }

  const latestVisualAction = getWorkspaceSegmentLatestVisualAction(segment);

  if (previewKind === "image") {
    const stillPreviewFallbackUrls = getWorkspaceSegmentStillPreviewUrls(segment);

    if (shouldUseWorkspaceSegmentAiPhotoRenderedStillPreview(segment)) {
      return getUniqueWorkspaceSegmentPreviewUrls([
        getWorkspaceSegmentVideoAssetPosterUrl(segment),
        ...stillPreviewFallbackUrls,
      ]);
    }

    if (latestVisualAction === "custom") {
      if (segment.customVideo?.source === "media-library") {
        return getUniqueWorkspaceSegmentPreviewUrls([
          getStudioCustomAssetPreviewUrl(segment.customVideo),
        ]);
      }

      return getUniqueWorkspaceSegmentPreviewUrls([
        getStudioCustomAssetPreviewUrl(segment.customVideo),
        ...stillPreviewFallbackUrls,
      ]);
    }

    if (latestVisualAction === "ai_photo") {
      return getUniqueWorkspaceSegmentPreviewUrls([
        getStudioCustomAssetPreviewUrl(segment.aiPhotoAsset),
        ...stillPreviewFallbackUrls,
      ]);
    }

    if (latestVisualAction === "image_edit") {
      return getUniqueWorkspaceSegmentPreviewUrls([
        getStudioCustomAssetPreviewUrl(segment.imageEditAsset),
        getStudioCustomAssetPreviewUrl(getWorkspaceSegmentPendingImageEditSourceAsset(segment)),
        ...stillPreviewFallbackUrls,
      ]);
    }

    if (latestVisualAction === "original") {
      return stillPreviewFallbackUrls;
    }

    if (latestVisualAction === "photo_animation" || latestVisualAction === "talking_photo") {
      return getUniqueWorkspaceSegmentPreviewUrls([
        getWorkspacePhotoAnimationSourcePosterUrl(segment),
        ...stillPreviewFallbackUrls,
      ]);
    }

    return stillPreviewFallbackUrls;
  }

  if (latestVisualAction === "ai" || latestVisualAction === "photo_animation" || latestVisualAction === "talking_photo") {
    const displayGeneratedVideoUrl =
      latestVisualAction === "ai"
        ? getWorkspaceSegmentDisplayAiVideoAssetUrl(segment, "ai_video")
        : latestVisualAction === "talking_photo"
          ? getWorkspaceSegmentDisplayAiVideoAssetUrl(segment, "talking_photo")
          : getWorkspaceSegmentDisplayAiVideoAssetUrl(segment, "photo_animation");

    if (!displayGeneratedVideoUrl) {
      return getUniqueWorkspaceSegmentPreviewUrls([
        segment.currentPlaybackUrl,
        segment.originalPlaybackUrl,
        segment.currentPreviewUrl,
        segment.originalPreviewUrl,
        ...getWorkspaceSegmentExternalVideoFallbackUrls(segment),
      ]);
    }

    // Generated video previews must never silently fall back to the original segment media.
    // Otherwise the UI can display the old source clip/photo when the generated asset
    // has a transient loading issue, which looks like the generation used the wrong source.
    return [];
  }

  if (latestVisualAction === "custom") {
    if (segment.customVideo?.source === "media-library" && getWorkspaceSegmentCustomPreviewKind(segment.customVideo) === "video") {
      return getUniqueWorkspaceSegmentPreviewUrls([getStudioCustomAssetPreviewUrl(segment.customVideo)]);
    }

    return getUniqueWorkspaceSegmentPreviewUrls([
      getStudioCustomAssetPreviewUrl(segment.customVideo),
      segment.currentPlaybackUrl,
      segment.originalPlaybackUrl,
      segment.currentPreviewUrl,
      segment.originalPreviewUrl,
      ...getWorkspaceSegmentExternalVideoFallbackUrls(segment),
    ]);
  }

  if (latestVisualAction === "original") {
    if (isWorkspaceSegmentServerPhotoAnimationOverride(segment)) {
      return getUniqueWorkspaceSegmentPreviewUrls([
        segment.currentPlaybackUrl,
        segment.currentExternalPlaybackUrl,
        segment.currentPreviewUrl,
        segment.currentExternalPreviewUrl,
      ]);
    }

    return getUniqueWorkspaceSegmentPreviewUrls([
      segment.originalPlaybackUrl,
      segment.originalExternalPlaybackUrl,
      segment.currentPlaybackUrl,
      segment.currentExternalPlaybackUrl,
      segment.originalPreviewUrl,
      segment.currentPreviewUrl,
      segment.originalExternalPreviewUrl,
      segment.currentExternalPreviewUrl,
    ]);
  }

  return getUniqueWorkspaceSegmentPreviewUrls([
    segment.currentPlaybackUrl,
    segment.originalPlaybackUrl,
    segment.currentPreviewUrl,
    segment.originalPreviewUrl,
    ...getWorkspaceSegmentExternalVideoFallbackUrls(segment),
  ]);
};

export const getWorkspaceSegmentDraftVideoUrl = (segment: WorkspaceSegmentEditorDraftSegment) => {
  if (segment.visualReset && !hasWorkspaceSegmentExplicitDraftVisual(segment)) {
    return getWorkspaceSegmentVisualResetVideoUrl(segment);
  }

  const latestVisualAction = getWorkspaceSegmentLatestVisualAction(segment);

  if (latestVisualAction === "ai") {
    return (
      getWorkspaceSegmentDisplayAiVideoAssetUrl(segment, "ai_video") ??
      segment.currentPlaybackUrl ??
      segment.currentExternalPlaybackUrl ??
      segment.originalPlaybackUrl ??
      segment.originalExternalPlaybackUrl ??
      segment.currentPreviewUrl ??
      segment.currentExternalPreviewUrl ??
      segment.originalPreviewUrl ??
      segment.originalExternalPreviewUrl
    );
  }

  if (latestVisualAction === "photo_animation") {
    return (
      getWorkspaceSegmentDisplayAiVideoAssetUrl(segment, "photo_animation") ??
      segment.currentPlaybackUrl ??
      segment.currentExternalPlaybackUrl ??
      segment.originalPlaybackUrl ??
      segment.originalExternalPlaybackUrl ??
      segment.currentPreviewUrl ??
      segment.currentExternalPreviewUrl ??
      segment.originalPreviewUrl ??
      segment.originalExternalPreviewUrl
    );
  }

  if (latestVisualAction === "talking_photo") {
    return (
      getWorkspaceSegmentDisplayAiVideoAssetUrl(segment, "talking_photo") ??
      segment.currentPlaybackUrl ??
      segment.currentExternalPlaybackUrl ??
      segment.originalPlaybackUrl ??
      segment.originalExternalPlaybackUrl ??
      segment.currentPreviewUrl ??
      segment.currentExternalPreviewUrl ??
      segment.originalPreviewUrl ??
      segment.originalExternalPreviewUrl
    );
  }

  if (segment.videoAction === "custom") {
    if (segment.customVideo?.source === "media-library") {
      return getStudioCustomAssetPreviewUrl(segment.customVideo);
    }

    return (
      getStudioCustomAssetPreviewUrl(segment.customVideo) ??
      segment.currentPlaybackUrl ??
      segment.currentExternalPlaybackUrl ??
      segment.originalPlaybackUrl ??
      segment.originalExternalPlaybackUrl ??
      segment.currentPreviewUrl ??
      segment.currentExternalPreviewUrl ??
      segment.originalPreviewUrl ??
      segment.originalExternalPreviewUrl
    );
  }

  if (segment.videoAction === "image_edit") {
    return (
      getStudioCustomAssetPreviewUrl(segment.imageEditAsset) ??
      segment.currentPlaybackUrl ??
      segment.currentExternalPlaybackUrl ??
      segment.originalPlaybackUrl ??
      segment.originalExternalPlaybackUrl ??
      segment.currentPreviewUrl ??
      segment.currentExternalPreviewUrl ??
      segment.originalPreviewUrl ??
      segment.originalExternalPreviewUrl
    );
  }

  if (segment.videoAction === "ai_photo") {
    return (
      getStudioCustomAssetPreviewUrl(segment.aiPhotoAsset) ??
      segment.currentPlaybackUrl ??
      segment.currentExternalPlaybackUrl ??
      segment.originalPlaybackUrl ??
      segment.originalExternalPlaybackUrl ??
      segment.currentPreviewUrl ??
      segment.currentExternalPreviewUrl ??
      segment.originalPreviewUrl ??
      segment.originalExternalPreviewUrl
    );
  }

  if (segment.videoAction === "original") {
    if (isWorkspaceSegmentServerPhotoAnimationOverride(segment)) {
      return (
        segment.currentPlaybackUrl ??
        segment.currentExternalPlaybackUrl ??
        segment.currentPreviewUrl ??
        segment.currentExternalPreviewUrl ??
        segment.originalPlaybackUrl ??
        segment.originalExternalPlaybackUrl ??
        segment.originalPreviewUrl ??
        segment.originalExternalPreviewUrl
      );
    }

    return (
      segment.originalPlaybackUrl ??
      segment.originalExternalPlaybackUrl ??
      segment.currentPlaybackUrl ??
      segment.currentExternalPlaybackUrl ??
      segment.originalPreviewUrl ??
      segment.originalExternalPreviewUrl ??
      segment.currentPreviewUrl ??
      segment.currentExternalPreviewUrl
    );
  }

  return (
    segment.currentPlaybackUrl ??
    segment.currentExternalPlaybackUrl ??
    segment.originalPlaybackUrl ??
    segment.originalExternalPlaybackUrl ??
    segment.currentPreviewUrl ??
    segment.currentExternalPreviewUrl ??
    segment.originalPreviewUrl ??
    segment.originalExternalPreviewUrl
  );
};

const getStudioCustomAssetMediaIdentityKey = (asset: StudioCustomVideoFile | null | undefined) => {
  if (!asset) {
    return null;
  }

  const previewUrl = getStudioCustomAssetPreviewUrl(asset);
  return [
    asset.source ? `source:${asset.source}` : "",
    asset.libraryItemKey ? `library:${asset.libraryItemKey}` : "",
    asset.assetId ? `asset:${asset.assetId}` : "",
    asset.mimeType ? `mime:${asset.mimeType}` : "",
    asset.fileName ? `file:${asset.fileName}` : "",
    previewUrl ? `preview:${getWorkspaceMediaLibraryAssetIdentityKey(previewUrl)}` : "",
    asset.posterUrl ? `poster:${getWorkspaceMediaLibraryAssetIdentityKey(asset.posterUrl)}` : "",
  ]
    .filter(Boolean)
    .join(",");
};

export const getWorkspaceSegmentMediaIdentityKey = (
  segment: WorkspaceSegmentEditorDraftSegment,
  mediaSurface?: Pick<WorkspaceResolvedMediaSurface, "displayUrl" | "posterUrl" | "previewKind" | "viewerUrl"> | null,
) => {
  const latestVisualAction = getWorkspaceSegmentLatestVisualAction(segment);
  const previewKind = mediaSurface?.previewKind ?? getWorkspaceSegmentPreviewKind(segment);
  const draftVisualAsset = getWorkspaceSegmentDraftVisualAsset(segment);
  const draftVisualIdentity = getStudioCustomAssetMediaIdentityKey(draftVisualAsset);
  const displayUrl = mediaSurface?.displayUrl ?? getWorkspaceSegmentDraftPreviewUrl(segment);
  const viewerUrl = mediaSurface?.viewerUrl ?? (previewKind === "video" ? getWorkspaceSegmentDraftVideoUrl(segment) : displayUrl);
  const posterUrl = mediaSurface?.posterUrl ?? (previewKind === "video" ? getWorkspaceSegmentDraftPosterUrl(segment) : null);

  return [
    `segment:${segment.index}`,
    `action:${segment.videoAction}`,
    `latest:${latestVisualAction}`,
    `kind:${previewKind}`,
    `reset:${segment.visualReset ? "1" : "0"}`,
    draftVisualIdentity ? `visual:${draftVisualIdentity}` : "",
    `current:${getWorkspaceSegmentCurrentVisualIdentityKey(segment) ?? "none"}`,
    `original:${getWorkspaceSegmentOriginalVisualIdentityKey(segment) ?? "none"}`,
    displayUrl ? `display:${getWorkspaceMediaLibraryAssetIdentityKey(displayUrl)}` : "display:none",
    viewerUrl ? `viewer:${getWorkspaceMediaLibraryAssetIdentityKey(viewerUrl)}` : "viewer:none",
    posterUrl ? `poster:${getWorkspaceMediaLibraryAssetIdentityKey(posterUrl)}` : "poster:none",
  ]
    .filter(Boolean)
    .join("|");
};

export const getWorkspaceSegmentResolvedMediaSurface = (
  segment: WorkspaceSegmentEditorDraftSegment,
  context: WorkspaceResolvedMediaContext,
  options?: { isPlaybackRequested?: boolean },
): WorkspaceResolvedMediaSurface => {
  const previewKind = getWorkspaceSegmentPreviewKind(segment);
  const previewUrl = getWorkspaceSegmentDraftPreviewUrl(segment);
  const viewerUrl = previewKind === "video" ? getWorkspaceSegmentDraftVideoUrl(segment) : previewUrl;
  const posterUrl = previewKind === "video" ? getWorkspaceSegmentDraftPosterUrl(segment) : null;
  const fallbackPosterUrl = previewKind === "video" ? getWorkspaceSegmentDraftFallbackPosterUrl(segment) : null;
  const fallbackUrls = getWorkspaceSegmentDraftPreviewFallbackUrls(segment, previewKind);
  const latestVisualAction = getWorkspaceSegmentLatestVisualAction(segment);

  return resolveWorkspaceMediaSurface({
    context,
    displayUrl: previewKind === "image" ? previewUrl : viewerUrl,
    fallbackPosterUrl,
    fallbackUrls,
    isGeneratedVideo:
      latestVisualAction === "ai" || latestVisualAction === "photo_animation" || latestVisualAction === "talking_photo",
    isPlaybackRequested: options?.isPlaybackRequested,
    posterUrl,
    previewKind,
    viewerUrl,
  });
};

export const getWorkspaceSegmentVisualDurationMeasurementUrl = (segment: WorkspaceSegmentEditorDraftSegment) => {
  if (getWorkspaceSegmentSelectedVisualPreviewKind(segment) !== "video") {
    return null;
  }

  const visualAsset = getWorkspaceSegmentDraftVisualAsset(segment);
  const visualAssetPreviewUrl = getStudioCustomAssetPreviewUrl(visualAsset);
  if (visualAssetPreviewUrl) {
    return visualAssetPreviewUrl;
  }

  const visualAssetId =
    getPositiveWorkspaceMediaAssetId(visualAsset?.assetId) ??
    getPositiveWorkspaceMediaAssetId(segment.currentAsset?.assetId) ??
    getPositiveWorkspaceMediaAssetId(segment.originalAsset?.assetId);
  if (visualAssetId) {
    return buildWorkspaceMediaAssetPlaybackUrl(visualAssetId);
  }

  const externalPlaybackUrl =
    segment.currentExternalPlaybackUrl ??
    segment.originalExternalPlaybackUrl ??
    segment.currentExternalPreviewUrl ??
    segment.originalExternalPreviewUrl;
  if (externalPlaybackUrl) {
    return externalPlaybackUrl;
  }

  return getWorkspaceSegmentDraftVideoUrl(segment);
};

const isWorkspaceMediaLibraryGeneratedPosterProxyUrl = (value: string | null | undefined) => {
  const normalizedValue = String(value ?? "").trim();
  return normalizedValue.includes("/api/workspace/media-library-preview");
};

const getWorkspaceMediaLibraryResolvedPosterUrl = (item: WorkspaceMediaLibraryItem) => {
  const assetPosterUrl = buildWorkspaceMediaLibraryAssetPosterUrl(item);
  const shouldPreferAssetPoster =
    item.previewKind === "video" &&
    Boolean(assetPosterUrl) &&
    (isWorkspaceMediaLibraryGeneratedPosterProxyUrl(item.previewPosterUrl) ||
      (item.kind === "photo_animation" && isStudioSegmentPhotoAnimationPosterUrl(item.previewPosterUrl)) ||
      (item.kind === "talking_photo" && isStudioSegmentTalkingPhotoPosterUrl(item.previewPosterUrl)) ||
      (item.kind === "ai_video" && isStudioSegmentAiVideoPosterUrl(item.previewPosterUrl)));

  if (shouldPreferAssetPoster) {
    return assetPosterUrl;
  }

  return item.previewPosterUrl || assetPosterUrl;
};

const getWorkspaceMediaLibrarySelectionPosterUrl = (item: WorkspaceMediaLibraryItem) => {
  if (item.previewKind !== "video") {
    return undefined;
  }

  const posterUrl = String(item.previewPosterUrl ?? "").trim();
  return posterUrl || undefined;
};

const getWorkspaceMediaLibraryResolvedMediaSurface = (
  item: WorkspaceMediaLibraryItem,
  context: WorkspaceResolvedMediaContext,
): WorkspaceResolvedMediaSurface =>
  resolveWorkspaceMediaSurface({
    context,
    displayUrl: item.previewUrl,
    isGeneratedVideo: item.kind === "ai_video" || item.kind === "photo_animation" || item.kind === "talking_photo",
    posterUrl: item.previewKind === "video" ? getWorkspaceMediaLibraryResolvedPosterUrl(item) : null,
    previewKind: item.previewKind,
    viewerUrl: item.previewUrl,
  });

const getWorkspaceSegmentPersistedSourceLabel = (segment: WorkspaceSegmentEditorDraftSegment) => {
  const persistedSourceKind = getWorkspaceSegmentPersistedSourceKind(segment);

  if (persistedSourceKind === "ai_generated") {
    return segment.mediaType === "photo" ? "ИИ фото" : "ИИ видео";
  }

  if (persistedSourceKind === "upload") {
    return "Свой визуал";
  }

  return "Сток";
};

export const getWorkspaceSegmentDraftSourceLabel = (segment: WorkspaceSegmentEditorDraftSegment) => {
  if (isWorkspaceSegmentVisualResetApplied(segment)) {
    return getWorkspaceSegmentPersistedSourceLabel(segment);
  }

  if (shouldUseWorkspaceSegmentAiPhotoRenderedStillPreview(segment)) {
    return "ИИ фото";
  }

  const latestVisualAction = getWorkspaceSegmentLatestVisualAction(segment);

  if (latestVisualAction === "custom") {
    return segment.customVideo?.source === "media-library" ? "Медиатека" : "Свой визуал";
  }

  if (latestVisualAction === "image_edit") {
    return "Дорисовка";
  }

  if (latestVisualAction === "ai_photo") {
    return "ИИ фото";
  }

  if (latestVisualAction === "photo_animation") {
    return "ИИ анимация";
  }

  if (latestVisualAction === "talking_photo") {
    return "Говорящий персонаж";
  }

  if (latestVisualAction === "ai") {
    return "ИИ видео";
  }

  return getWorkspaceSegmentPersistedSourceLabel(segment);
};

export const getWorkspaceSegmentDraftSourceDisplayLabel = (sourceLabel: string, locale: Locale) => {
  if (locale !== "en") {
    return sourceLabel;
  }

  switch (sourceLabel) {
    case "Сток":
      return "Stock";
    case "ИИ фото":
      return "AI photo";
    case "Медиатека":
      return "Media library";
    case "Свой визуал":
      return "Custom visual";
    case "Дорисовка":
      return "Image edit";
    case "ИИ анимация":
      return "AI animation";
    case "Говорящий персонаж":
      return "Talking character";
    case "ИИ видео":
      return "AI video";
    default:
      return sourceLabel;
  }
};

const getWorkspaceSegmentEditorDisplayedTimeTenths = (value: number) => {
  const safeValue = Number.isFinite(value) ? Math.max(0, value) : 0;
  return Math.round(safeValue * 10);
};

const formatWorkspaceSegmentDecimalPart = (tenths: number) =>
  tenths > 0 ? `.${tenths}` : "";

const formatWorkspaceSegmentDurationNumber = (seconds: number, _locale: Locale) => {
  const totalTenths = getWorkspaceSegmentEditorDisplayedTimeTenths(seconds);
  const wholeSeconds = Math.floor(totalTenths / 10);
  const tenths = totalTenths % 10;
  const label = `${wholeSeconds}${formatWorkspaceSegmentDecimalPart(tenths)}`;

  return label;
};

const formatWorkspaceSegmentEditorTime = (value: number) => {
  const totalTenths = getWorkspaceSegmentEditorDisplayedTimeTenths(value);
  const wholeTotalSeconds = Math.floor(totalTenths / 10);
  const tenths = totalTenths % 10;
  const hours = Math.floor(wholeTotalSeconds / 3600);
  const minutes = Math.floor((wholeTotalSeconds % 3600) / 60);
  const seconds = wholeTotalSeconds % 60;
  const secondsLabel = `${String(seconds).padStart(2, "0")}${formatWorkspaceSegmentDecimalPart(tenths)}`;

  if (hours > 0) {
    return `${String(hours).padStart(2, "0")}:${String(minutes).padStart(2, "0")}:${secondsLabel}`;
  }

  return `${String(minutes).padStart(2, "0")}:${secondsLabel}`;
};

const getWorkspaceVideoPlayerDisplayedSeconds = (value: number, mode: "current" | "duration" = "current") => {
  const safeValue = Number.isFinite(value) ? Math.max(0, value) : 0;
  return mode === "duration" ? Math.ceil(safeValue) : Math.floor(safeValue);
};

const formatWorkspaceVideoPlayerTime = (value: number, mode?: "current" | "duration") => {
  const wholeTotalSeconds = getWorkspaceVideoPlayerDisplayedSeconds(value, mode);
  const hours = Math.floor(wholeTotalSeconds / 3600);
  const minutes = Math.floor((wholeTotalSeconds % 3600) / 60);
  const seconds = wholeTotalSeconds % 60;
  const secondsLabel = String(seconds).padStart(2, "0");

  if (hours > 0) {
    return `${String(hours).padStart(2, "0")}:${String(minutes).padStart(2, "0")}:${secondsLabel}`;
  }

  return `${String(minutes).padStart(2, "0")}:${secondsLabel}`;
};

export const formatWorkspaceSegmentEditorSegmentTimeRange = (
  startTime: number,
  endTime: number,
  _options?: {
    isFirstSegment?: boolean;
  },
) => {
  const startLabel = formatWorkspaceSegmentEditorTime(startTime);
  const endLabel = formatWorkspaceSegmentEditorTime(endTime);

  return `${startLabel} - ${endLabel}`;
};

export const formatWorkspaceSegmentEditorSegmentDurationLabel = (
  startTime: number,
  endTime: number,
  locale: Locale,
  _options?: {
    isFirstSegment?: boolean;
  },
) => {
  const durationSeconds = Math.max(0, endTime - startTime);
  const durationLabel = formatWorkspaceSegmentDurationNumber(durationSeconds, locale);
  return locale === "en" ? `${durationLabel}s` : `${durationLabel} с`;
};

const formatWorkspaceSegmentEditorDurationBadgeLabel = (seconds: number, locale: Locale) => {
  const durationLabel = formatWorkspaceSegmentDurationNumber(seconds, locale);
  return locale === "en" ? `${durationLabel}s` : `${durationLabel} сек`;
};

const formatWorkspaceSegmentExtensionDurationLabel = (seconds: number, locale: Locale) => {
  const safeSeconds = Number.isFinite(seconds) ? Math.max(0, seconds) : 0;
  const roundedSeconds = safeSeconds >= 10 ? Math.round(safeSeconds) : Math.round(safeSeconds * 10) / 10;
  const normalizedLabel = Number.isInteger(roundedSeconds)
    ? String(roundedSeconds)
    : String(roundedSeconds).replace(".", ",");

  return locale === "en" ? `+${normalizedLabel}s` : `+${normalizedLabel} с`;
};

const buildWorkspaceSegmentAiExtensionPrompt = (
  extensionPlan: NonNullable<ReturnType<typeof getWorkspaceSegmentDurationExtensionPlan>>,
  locale: Locale,
) =>
  workspaceText(
    locale,
    `Продли сцену из последнего кадра на ${formatWorkspaceSegmentExtensionDurationLabel(extensionPlan.extraDurationSeconds, locale)}. Сохрани стиль, объект, свет и плавное естественное движение без резких переходов.`,
    `Extend the scene from the last frame by ${formatWorkspaceSegmentExtensionDurationLabel(extensionPlan.extraDurationSeconds, locale)}. Keep the same style, subject, lighting, and smooth natural motion without abrupt cuts.`,
  );

const isWorkspaceSegmentDefaultAiExtensionPrompt = (value: string | null | undefined) => {
  const normalizedValue = normalizeWorkspaceLocalizedTextForCompare(value).toLowerCase();
  return (
    normalizedValue.startsWith("продли сцену из последнего кадра на +") ||
    normalizedValue.startsWith("extend the scene from the last frame by +")
  );
};

const parseWorkspaceSegmentEditorTimeInput = (value: string) => {
  const normalizedValue = value.trim().replace(",", ".");
  if (!normalizedValue) {
    return null;
  }

  if (!normalizedValue.includes(":")) {
    const seconds = Number(normalizedValue);
    return Number.isFinite(seconds) && seconds >= 0 ? seconds : null;
  }

  const parts = normalizedValue.split(":").map((part) => part.trim());
  if (parts.length < 2 || parts.length > 3 || parts.some((part) => part === "")) {
    return null;
  }

  const numbers = parts.map((part) => Number(part));
  if (numbers.some((part) => !Number.isFinite(part) || part < 0)) {
    return null;
  }

  if (numbers.length === 2) {
    const [minutes, seconds] = numbers;
    return minutes * 60 + seconds;
  }

  const [hours, minutes, seconds] = numbers;
  return hours * 3600 + minutes * 60 + seconds;
};

const parseWorkspaceSegmentEditorDurationInput = (value: string) => {
  const normalizedValue = value
    .trim()
    .replace(/\s*(?:сек(?:\.|унд[аы]?)?|seconds?|secs?|s|с)$/iu, "")
    .trim();

  return parseWorkspaceSegmentEditorTimeInput(normalizedValue);
};

export const getWorkspaceSegmentEditorGenerationOverrides = (
  session?: WorkspaceSegmentEditorDraftSession | null,
) => {
  const voiceEnabled = normalizeWorkspaceSegmentEditorSetting(session?.voiceType) !== "none";
  const subtitleEnabled = voiceEnabled && normalizeWorkspaceSegmentEditorSetting(session?.subtitleType) !== "none";

  return {
    language:
      normalizeStudioLanguageValue(session?.language) ?? getStudioLanguageForVoiceId(session?.voiceType) ?? undefined,
    musicType: normalizeWorkspaceSegmentEditorSetting(session?.musicType),
    subtitleEnabled,
    subtitleColorId: subtitleEnabled ? normalizeWorkspaceSegmentEditorSetting(session?.subtitleColor) : undefined,
    subtitleStyleId: subtitleEnabled ? normalizeWorkspaceSegmentEditorSetting(session?.subtitleStyle) : undefined,
    voiceEnabled,
    voiceId: voiceEnabled ? normalizeWorkspaceSegmentEditorSetting(session?.voiceType) : undefined,
  };
};

const isTextInputTarget = (target: EventTarget | null) =>
  target instanceof HTMLElement &&
  (target.tagName === "INPUT" || target.tagName === "TEXTAREA" || target.isContentEditable);

const normalizeWorkspacePlan = (value: unknown) => {
  const normalized = String(value ?? "").trim().toUpperCase();
  return normalized || null;
};

const normalizeWorkspaceBalance = (value: unknown) => {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? Math.max(0, parsed) : null;
};

const normalizeWorkspaceExpiry = (value: unknown) => {
  const normalized = String(value ?? "").trim();
  return normalized || null;
};

const normalizeWorkspaceStartPlanUsed = (value: unknown, plan: unknown) => {
  if (typeof value === "boolean") return value;
  if (typeof value === "number" && Number.isFinite(value)) return value !== 0;

  const normalized = String(value ?? "").trim().toLowerCase();
  if (["1", "true", "yes", "y", "on"].includes(normalized)) return true;
  if (["0", "false", "no", "n", "off"].includes(normalized)) return false;
  return normalizeWorkspacePlan(plan) === "START";
};

const areWorkspaceProfilesEqual = (left: WorkspaceProfile | null | undefined, right: WorkspaceProfile | null | undefined) =>
  normalizeWorkspacePlan(left?.plan) === normalizeWorkspacePlan(right?.plan) &&
  normalizeWorkspaceBalance(left?.balance) === normalizeWorkspaceBalance(right?.balance) &&
  normalizeWorkspaceExpiry(left?.expiresAt) === normalizeWorkspaceExpiry(right?.expiresAt) &&
  normalizeWorkspaceStartPlanUsed(left?.startPlanUsed, left?.plan) ===
    normalizeWorkspaceStartPlanUsed(right?.startPlanUsed, right?.plan);

const STUDIO_PREVIEW_DISMISS_STORAGE_KEY_PREFIX = "adshorts.studio-preview-dismiss:";
const STUDIO_MEDIA_LIBRARY_HIDDEN_STORAGE_KEY_PREFIX = "adshorts.media-library-hidden:";
const STUDIO_CONTENT_PLAN_VISIBILITY_STORAGE_KEY_PREFIX = "adshorts.content-plan-visible:";
const STUDIO_BRAND_SETTINGS_STORAGE_KEY_PREFIX = "adshorts.studio-brand:";

const normalizeWorkspaceEmail = (value: string | null | undefined) => String(value ?? "").trim().toLowerCase();

const sanitizeWorkspaceContentPlanIdeaPrompt = (value: unknown) => {
  const fallbackPrompt = String(value ?? "").replace(/\s+/g, " ").trim();
  if (!fallbackPrompt) {
    return "";
  }

  let normalized = fallbackPrompt.replace(/^["'`]+|["'`]+$/g, "").trim();
  const leadingInstructionPatterns = [
    /^(?:напиши|создай|сделай)\s+(?:мне\s+)?(?:сценарий\s+)?(?:для\s+)?(?:shorts|шортс)(?:\s+(?:ролика|видео))?\s*(?:[,:-]\s*)?(?:где\s+|про\s+|о\s+|об\s+|на\s+тему\s+)?/i,
    /^(?:создай|сделай)\s+(?:мне\s+)?(?:shorts|шортс|ролик|видео)(?:\s+(?:о|об|про|на\s+тему))?\s*(?:[,:-]\s*)?/i,
    /^write\s+(?:a\s+)?(?:shorts?\s+)?script(?:\s+for\s+(?:a\s+)?)?(?:shorts?\s+video)?\s*(?:[,:-]\s*)?(?:about\s+|on\s+|where\s+)?/i,
    /^(?:create|make)\s+(?:a\s+)?shorts?(?:\s+video)?\s*(?:[,:-]\s*)?(?:about\s+|on\s+)?/i,
  ];

  for (const pattern of leadingInstructionPatterns) {
    const nextValue = normalized.replace(pattern, "").trim();
    if (nextValue && nextValue !== normalized) {
      normalized = nextValue;
      break;
    }
  }

  normalized = normalized.replace(/^[\s,.:;-]+/, "").replace(/^["'`]+|["'`]+$/g, "").trim();
  return normalized || fallbackPrompt;
};

const normalizeWorkspaceContentPlanSourceMatchText = (value: unknown) =>
  String(value ?? "")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/^["'`]+|["'`]+$/g, "")
    .trim()
    .toLocaleLowerCase();

const isWorkspaceContentPlanSourceIdeaSynchronized = (
  prompt: string,
  sourceIdea: WorkspaceContentPlanComposerSource | null | undefined,
) => {
  if (!sourceIdea) {
    return false;
  }

  const normalizedPrompt = normalizeWorkspaceContentPlanSourceMatchText(prompt);
  const normalizedSourcePrompt = normalizeWorkspaceContentPlanSourceMatchText(sourceIdea.prompt);
  return Boolean(normalizedPrompt) && normalizedPrompt === normalizedSourcePrompt;
};

const getStudioPreviewDismissStorageKey = (email: string) => `${STUDIO_PREVIEW_DISMISS_STORAGE_KEY_PREFIX}${email}`;
const getStudioMediaLibraryHiddenStorageKey = (email: string) => `${STUDIO_MEDIA_LIBRARY_HIDDEN_STORAGE_KEY_PREFIX}${email}`;
const getStudioContentPlanVisibilityStorageKey = (email: string) =>
  `${STUDIO_CONTENT_PLAN_VISIBILITY_STORAGE_KEY_PREFIX}${email}`;
const getStudioBrandSettingsStorageKey = (email: string) => `${STUDIO_BRAND_SETTINGS_STORAGE_KEY_PREFIX}${email}`;

type StudioBrandSettingsSnapshot = {
  brandLogoFile: StudioBrandLogoFile | null;
  brandText: string;
};

type StoredStudioBrandSettings = {
  brandLogoFile?: {
    dataUrl?: string;
    fileName?: string;
    fileSize?: number;
    mimeType?: string;
  } | null;
  brandText?: string;
};

const inferStudioBrandLogoExtension = (mimeType: string) => {
  const normalized = mimeType.trim().toLowerCase();
  if (normalized === "image/avif") return ".avif";
  if (normalized === "image/png") return ".png";
  if (normalized === "image/webp") return ".webp";
  return ".jpg";
};

const readStoredStudioBrandSettings = (email: string | null | undefined): StudioBrandSettingsSnapshot => {
  if (typeof window === "undefined") {
    return { brandLogoFile: null, brandText: "" };
  }

  const normalizedEmail = normalizeWorkspaceEmail(email);
  if (!normalizedEmail) {
    return { brandLogoFile: null, brandText: "" };
  }

  try {
    const rawValue = window.localStorage.getItem(getStudioBrandSettingsStorageKey(normalizedEmail));
    if (!rawValue) {
      return { brandLogoFile: null, brandText: "" };
    }

    const parsed = JSON.parse(rawValue) as StoredStudioBrandSettings | null;
    const brandText = String(parsed?.brandText ?? "").slice(0, STUDIO_BRAND_TEXT_MAX_CHARS);
    const storedLogo = parsed?.brandLogoFile && typeof parsed.brandLogoFile === "object" ? parsed.brandLogoFile : null;
    const dataUrl = String(storedLogo?.dataUrl ?? "").trim();
    const mimeType =
      String(storedLogo?.mimeType ?? "").trim() ||
      String(dataUrl.match(/^data:([^;,]+);base64,/i)?.[1] ?? "").trim() ||
      "image/png";
    const fileSize = Math.max(0, Number(storedLogo?.fileSize ?? 0) || 0);
    const rawFileName = String(storedLogo?.fileName ?? "").trim();
    const fileName = isSupportedStudioBrandLogoFile(rawFileName)
      ? rawFileName
      : `brand-logo${inferStudioBrandLogoExtension(mimeType)}`;

    if (!dataUrl || !dataUrl.startsWith("data:image/") || fileSize > STUDIO_BRAND_LOGO_MAX_BYTES) {
      return { brandLogoFile: null, brandText };
    }

    return {
      brandLogoFile: {
        dataUrl,
        fileName,
        fileSize,
        mimeType,
      },
      brandText,
    };
  } catch {
    return { brandLogoFile: null, brandText: "" };
  }
};

const persistStudioBrandSettings = (
  email: string | null | undefined,
  settings: StudioBrandSettingsSnapshot,
) => {
  if (typeof window === "undefined") {
    return;
  }

  const normalizedEmail = normalizeWorkspaceEmail(email);
  if (!normalizedEmail) {
    return;
  }

  try {
    const storageKey = getStudioBrandSettingsStorageKey(normalizedEmail);
    const brandText = settings.brandText.trim().slice(0, STUDIO_BRAND_TEXT_MAX_CHARS);
    const logoDataUrl = String(settings.brandLogoFile?.dataUrl ?? "").trim();
    const payload: StoredStudioBrandSettings = {
      brandText,
      brandLogoFile:
        settings.brandLogoFile && logoDataUrl
          ? {
              dataUrl: logoDataUrl,
              fileName: settings.brandLogoFile.fileName,
              fileSize: settings.brandLogoFile.fileSize,
              mimeType: settings.brandLogoFile.mimeType,
            }
          : null,
    };

    if (!payload.brandText && !payload.brandLogoFile) {
      window.localStorage.removeItem(storageKey);
      return;
    }

    window.localStorage.setItem(storageKey, JSON.stringify(payload));
  } catch {
    // Ignore storage quota errors.
  }
};

const normalizeStudioBrandSettingsText = (value: string | null | undefined) =>
  String(value ?? "").trim().slice(0, STUDIO_BRAND_TEXT_MAX_CHARS);

const getStudioBrandLogoComparableKey = (brandLogoFile: StudioBrandLogoFile | null | undefined) => {
  if (!brandLogoFile) {
    return "";
  }

  return [
    String(brandLogoFile.assetId ?? ""),
    String(brandLogoFile.dataUrl ?? ""),
    String(brandLogoFile.objectUrl ?? ""),
    String(brandLogoFile.fileName ?? ""),
    String(brandLogoFile.mimeType ?? ""),
    String(brandLogoFile.fileSize ?? ""),
  ].join("|");
};

const areStudioBrandSettingsEqual = (
  left: StudioBrandSettingsSnapshot,
  right: StudioBrandSettingsSnapshot,
) =>
  normalizeStudioBrandSettingsText(left.brandText) === normalizeStudioBrandSettingsText(right.brandText) &&
  getStudioBrandLogoComparableKey(left.brandLogoFile) === getStudioBrandLogoComparableKey(right.brandLogoFile);

const normalizeStoredStudioBrandLogoFile = (value: unknown): StudioBrandLogoFile | null => {
  if (!value || typeof value !== "object") {
    return null;
  }

  const record = value as Partial<StudioBrandLogoFile>;
  const assetId = Number.isFinite(Number(record.assetId)) && Number(record.assetId) > 0
    ? Math.trunc(Number(record.assetId))
    : undefined;
  const dataUrl = String(record.dataUrl ?? "").trim();
  const mimeType =
    String(record.mimeType ?? "").trim() ||
    String(dataUrl.match(/^data:([^;,]+);base64,/i)?.[1] ?? "").trim() ||
    "image/png";
  const fileSize = Math.max(0, Number(record.fileSize ?? 0) || 0);
  const rawFileName = String(record.fileName ?? "").trim();
  const fileName = isSupportedStudioBrandLogoFile(rawFileName)
    ? rawFileName
    : `brand-logo${inferStudioBrandLogoExtension(mimeType)}`;

  if (!assetId && (!dataUrl || !dataUrl.startsWith("data:image/"))) {
    return null;
  }

  if (fileSize > STUDIO_BRAND_LOGO_MAX_BYTES) {
    return null;
  }

  return {
    assetId,
    dataUrl: dataUrl || undefined,
    fileName,
    fileSize,
    mimeType,
  };
};

const normalizeWorkspaceSegmentEditorProjectBrandState = (
  value: unknown,
  fallback?: WorkspaceSegmentEditorProjectBrandState | null,
): WorkspaceSegmentEditorProjectBrandState => {
  const record = value && typeof value === "object" ? (value as Record<string, unknown>) : {};

  return {
    brandLogoFile:
      normalizeStoredStudioBrandLogoFile(record.brandLogoFile) ??
      normalizeStoredStudioBrandLogoFile(record.brand_logo_file) ??
      fallback?.brandLogoFile ??
      null,
    brandText: normalizeStudioBrandSettingsText(String(record.brandText ?? record.brand_text ?? fallback?.brandText ?? "")),
    systemWatermarkEnabled:
      typeof record.systemWatermarkEnabled === "boolean"
        ? record.systemWatermarkEnabled
        : typeof record.system_watermark_enabled === "boolean"
          ? record.system_watermark_enabled
          : Boolean(fallback?.systemWatermarkEnabled),
  };
};

export const createWorkspaceSegmentEditorProjectBrandState = (
  options?: {
    brandLogoFile?: StudioBrandLogoFile | null;
    brandText?: string | null;
    systemWatermarkEnabled?: boolean;
  } | null,
): WorkspaceSegmentEditorProjectBrandState => ({
  brandLogoFile: options?.brandLogoFile ?? null,
  brandText: normalizeStudioBrandSettingsText(options?.brandText),
  systemWatermarkEnabled: Boolean(options?.systemWatermarkEnabled),
});

export const areWorkspaceSegmentEditorProjectBrandStatesEqual = (
  left: WorkspaceSegmentEditorProjectBrandState,
  right: WorkspaceSegmentEditorProjectBrandState,
) =>
  areStudioBrandSettingsEqual(left, right) &&
  left.systemWatermarkEnabled === right.systemWatermarkEnabled;

export const resolveWorkspaceSegmentEditorProjectBrandSnapshot = (options: {
  defaultState: WorkspaceSegmentEditorProjectBrandState;
  storedSnapshot?: WorkspaceSegmentEditorProjectBrandSnapshot | null;
}): WorkspaceSegmentEditorProjectBrandSnapshot => {
  const baseline = options.storedSnapshot?.baseline ?? options.defaultState;
  return {
    applied: options.storedSnapshot?.applied ?? baseline,
    baseline,
  };
};

const serializeWorkspaceSegmentEditorProjectBrandState = (
  state: WorkspaceSegmentEditorProjectBrandState,
) => {
  const brandLogoFile = normalizeStoredStudioBrandLogoFile(state.brandLogoFile);

  return {
    brandLogoFile: brandLogoFile
      ? {
          assetId: brandLogoFile.assetId,
          dataUrl: brandLogoFile.dataUrl,
          fileName: brandLogoFile.fileName,
          fileSize: brandLogoFile.fileSize,
          mimeType: brandLogoFile.mimeType,
        }
      : null,
    brandText: normalizeStudioBrandSettingsText(state.brandText),
    systemWatermarkEnabled: Boolean(state.systemWatermarkEnabled),
  };
};

const normalizeWorkspaceSegmentEditorProjectBrandSnapshot = (
  value: unknown,
): WorkspaceSegmentEditorProjectBrandSnapshot | null => {
  if (!value || typeof value !== "object") {
    return null;
  }

  const record = value as Record<string, unknown>;
  const hasNestedSnapshot = Boolean(record.baseline || record.applied);
  const baseline = hasNestedSnapshot
    ? normalizeWorkspaceSegmentEditorProjectBrandState(record.baseline)
    : normalizeWorkspaceSegmentEditorProjectBrandState(record);
  const applied = hasNestedSnapshot
    ? normalizeWorkspaceSegmentEditorProjectBrandState(record.applied, baseline)
    : baseline;

  return { applied, baseline };
};

export const readStoredWorkspaceSegmentEditorBrandSnapshot = (
  email: string | null | undefined,
  projectId: number | null | undefined,
) => {
  if (typeof window === "undefined") {
    return null;
  }

  const normalizedEmail = normalizeWorkspaceSegmentEditorStorageEmail(email);
  const normalizedProjectId = Number(projectId);
  if (!normalizedEmail || !Number.isInteger(normalizedProjectId) || normalizedProjectId <= 0) {
    return null;
  }

  const storageKey = getWorkspaceSegmentEditorBrandStorageKey(normalizedEmail, normalizedProjectId);

  for (const candidate of readWorkspaceSegmentEditorStorageCandidates(storageKey)) {
    try {
      const parsedValue = JSON.parse(candidate.rawValue) as unknown;
      const normalizedSnapshot = normalizeWorkspaceSegmentEditorProjectBrandSnapshot(parsedValue);
      if (!normalizedSnapshot) {
        removeWorkspaceSegmentEditorStorageValueFrom(candidate.storageName, storageKey);
        continue;
      }

      if (candidate.storageName === "sessionStorage") {
        writeWorkspaceSegmentEditorStorageValue(
          storageKey,
          JSON.stringify({
            applied: serializeWorkspaceSegmentEditorProjectBrandState(normalizedSnapshot.applied),
            baseline: serializeWorkspaceSegmentEditorProjectBrandState(normalizedSnapshot.baseline),
          }),
        );
      }

      return normalizedSnapshot;
    } catch {
      removeWorkspaceSegmentEditorStorageValueFrom(candidate.storageName, storageKey);
    }
  }

  return null;
};

export const writeStoredWorkspaceSegmentEditorBrandSnapshot = (
  email: string | null | undefined,
  projectId: number | null | undefined,
  snapshot: WorkspaceSegmentEditorProjectBrandSnapshot,
) => {
  if (typeof window === "undefined") {
    return;
  }

  const normalizedEmail = normalizeWorkspaceSegmentEditorStorageEmail(email);
  const normalizedProjectId = Number(projectId);
  if (!normalizedEmail || !Number.isInteger(normalizedProjectId) || normalizedProjectId <= 0) {
    return;
  }

  writeWorkspaceSegmentEditorStorageValue(
    getWorkspaceSegmentEditorBrandStorageKey(normalizedEmail, normalizedProjectId),
    JSON.stringify({
      applied: serializeWorkspaceSegmentEditorProjectBrandState(snapshot.applied),
      baseline: serializeWorkspaceSegmentEditorProjectBrandState(snapshot.baseline),
    }),
  );
};

const removeStoredWorkspaceSegmentEditorBrandSnapshot = (
  email: string | null | undefined,
  projectId: number | null | undefined,
) => {
  if (typeof window === "undefined") {
    return;
  }

  const normalizedEmail = normalizeWorkspaceSegmentEditorStorageEmail(email);
  const normalizedProjectId = Number(projectId);
  if (!normalizedEmail || !Number.isInteger(normalizedProjectId) || normalizedProjectId <= 0) {
    return;
  }

  removeWorkspaceSegmentEditorStorageValue(getWorkspaceSegmentEditorBrandStorageKey(normalizedEmail, normalizedProjectId));
};

const getWorkspaceMediaLibraryItemStorageKey = (item: WorkspaceMediaLibraryItem) => item.itemKey;

const getWorkspaceMediaLibraryItemKindLabel = (
  kind: WorkspaceMediaLibraryItemKind,
  assetKind?: string | null,
  locale: Locale = "ru",
) => {
  const normalizedAssetKind = String(assetKind ?? "").trim().toLowerCase();
  if (normalizedAssetKind === "final_video") {
    return workspaceText(locale, "Готовое видео", "Finished video");
  }

  if (normalizedAssetKind === "custom_video" || normalizedAssetKind === "segment_source") {
    return workspaceText(locale, "Загруженное видео", "Uploaded video");
  }

  if (normalizedAssetKind === "brand_logo" || normalizedAssetKind === "uploaded_photo") {
    return workspaceText(locale, "Загруженное фото", "Uploaded photo");
  }

  if (kind === "photo_animation") {
    return workspaceText(locale, "ИИ анимация фото", "AI photo animation");
  }

  if (kind === "talking_photo") {
    return workspaceText(locale, "Говорящий персонаж", "Talking character");
  }

  if (kind === "ai_video") {
    return workspaceText(locale, "ИИ видео", "AI video");
  }

  if (kind === "image_edit") {
    return workspaceText(locale, "Дорисовать", "Image edit");
  }

  if (kind === "character_reference") {
    return workspaceText(locale, "Персонаж", "Character");
  }

  if (kind === "scene_reference") {
    return workspaceText(locale, "Сцена", "Scene");
  }

  return workspaceText(locale, "ИИ фото", "AI photo");
};

const renderWorkspaceMediaLibraryPlayOverlay = (previewKind: WorkspaceMediaLibraryPreviewKind): ReactNode => {
  if (previewKind !== "video") {
    return null;
  }

  return (
    <span className="studio-media-library__play-indicator" aria-hidden="true">
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none" aria-hidden="true">
        <path d="M9 7.5v9l7-4.5-7-4.5Z" fill="currentColor" />
      </svg>
    </span>
  );
};

const getWorkspaceMediaLibraryItemMimeType = (item: WorkspaceMediaLibraryItem) =>
  item.previewKind === "video" ? "video/mp4" : "image/jpeg";

const getWorkspaceMediaLibraryItemAssetId = (item: Pick<WorkspaceMediaLibraryItem, "assetId">) =>
  getPositiveWorkspaceMediaAssetId(item.assetId);

const getWorkspaceMediaLibraryCanonicalAssetRouteId = (
  value: string | null | undefined,
  previewKind: WorkspaceMediaLibraryPreviewKind,
) => {
  const normalizedValue = String(value ?? "").trim();
  if (!normalizedValue) {
    return null;
  }

  try {
    const url = new URL(normalizedValue, "http://localhost");
    const match = url.pathname.match(/^\/api\/workspace\/media-assets\/(\d+)(?:\/(playback))?$/i);
    if (!match) {
      return null;
    }

    const assetId = getPositiveWorkspaceMediaAssetId(match[1]);
    if (!assetId) {
      return null;
    }

    const isPlaybackRoute = match[2] === "playback";
    if (previewKind === "video" && !isPlaybackRoute) {
      return null;
    }

    if (previewKind === "image" && isPlaybackRoute) {
      return null;
    }

    return assetId;
  } catch {
    return null;
  }
};

export const getWorkspaceMediaLibraryItemRemoteUrl = (item: WorkspaceMediaLibraryItem) => {
  const assetId = getWorkspaceMediaLibraryItemAssetId(item);
  const mimeType = getWorkspaceMediaLibraryItemMimeType(item);

  if (item.source === "persisted" && assetId) {
    return getWorkspaceMediaAssetResolvedPreviewUrl({
      assetId,
      fileName: item.downloadName,
      mimeType,
    });
  }

  const previewUrl = String(item.previewUrl ?? "").trim();
  if (previewUrl) {
    return previewUrl;
  }

  return getWorkspaceMediaAssetResolvedPreviewUrl({
    assetId,
    fileName: item.downloadName,
    mimeType,
    remoteUrl: item.downloadUrl,
  });
};

const getWorkspaceMediaLibrarySelectionAssetId = (item: WorkspaceMediaLibraryItem) => {
  const assetId = getWorkspaceMediaLibraryItemAssetId(item);
  if (!assetId) {
    return undefined;
  }

  if (item.source === "persisted") {
    return assetId;
  }

  const selectionRemoteUrl = getWorkspaceMediaLibraryItemRemoteUrl(item);
  return getWorkspaceMediaLibraryCanonicalAssetRouteId(selectionRemoteUrl, item.previewKind) === assetId
    ? assetId
    : undefined;
};

export const createStudioCustomVideoFileFromMediaLibraryItem = (
  item: WorkspaceMediaLibraryItem,
): StudioCustomVideoFile => ({
  assetId: getWorkspaceMediaLibrarySelectionAssetId(item),
  fileName: item.downloadName,
  fileSize: 0,
  libraryItemKey: getWorkspaceMediaLibraryItemStorageKey(item),
  mimeType: getWorkspaceMediaLibraryItemMimeType(item),
  posterUrl: getWorkspaceMediaLibrarySelectionPosterUrl(item),
  remoteUrl: getWorkspaceMediaLibraryItemRemoteUrl(item) ?? undefined,
  source: "media-library",
});

const getWorkspaceGeneratedMediaLibraryRestoreKey = (
  projectId: number,
  segmentIndex: number,
  kind: WorkspaceMediaLibraryItemKind,
) => `${projectId}:${segmentIndex}:${kind}`;

const doesWorkspaceGeneratedMediaLibraryItemMatchSegmentVisual = (
  segment: WorkspaceSegmentEditorDraftSegment,
  item: WorkspaceMediaLibraryItem,
) => {
  const itemAssetId = Number(item.assetId);
  const itemAssetIdentity = Number.isFinite(itemAssetId) && itemAssetId > 0 ? `asset:${Math.trunc(itemAssetId)}` : null;
  if (itemAssetIdentity) {
    const segmentAssetIdentities = [
      getWorkspaceMediaAssetIdentityKey(segment.currentAsset),
      getWorkspaceMediaAssetIdentityKey(segment.originalAsset),
    ].filter(Boolean);
    if (segmentAssetIdentities.includes(itemAssetIdentity)) {
      return true;
    }
  }

  const itemUrls = getUniqueWorkspaceSegmentPreviewUrls([item.previewUrl, item.previewPosterUrl, item.downloadUrl]);
  if (!itemUrls.length) {
    return false;
  }

  const segmentUrls = getUniqueWorkspaceSegmentPreviewUrls([
    segment.currentExternalPlaybackUrl,
    segment.currentExternalPreviewUrl,
    segment.currentPlaybackUrl,
    segment.currentPreviewUrl,
    segment.originalExternalPlaybackUrl,
    segment.originalExternalPreviewUrl,
    segment.originalPlaybackUrl,
    segment.originalPreviewUrl,
  ]);

  return itemUrls.some((itemUrl) => segmentUrls.includes(itemUrl));
};

const shouldHydrateWorkspaceGeneratedMediaLibraryItem = (
  segment: WorkspaceSegmentEditorDraftSegment,
  item: WorkspaceMediaLibraryItem,
  options: {
    allowPersistedGeneratedVideoRecovery?: boolean;
    allowExplicitDraftVisual?: boolean;
    videoAction: WorkspaceSegmentEditorVideoAction;
    aiVideoMode?: WorkspaceSegmentAiVideoMode;
  },
) => {
  if (isWorkspaceSegmentEditorDraftSegmentEmpty(segment)) {
    return false;
  }

  if (segment.visualReset) {
    return false;
  }

  const hasExplicitDraftVisual = hasWorkspaceSegmentExplicitDraftVisual(segment);
  if (hasExplicitDraftVisual && !options.allowExplicitDraftVisual) {
    return false;
  }

  if (
    segment.videoAction === options.videoAction ||
    (options.aiVideoMode && segment.aiVideoGeneratedMode === options.aiVideoMode)
  ) {
    return true;
  }

  if (
    options.allowPersistedGeneratedVideoRecovery &&
    item.source === "persisted" &&
    item.previewKind === "video" &&
    item.kind === "talking_photo" &&
    !segment.aiVideoAsset &&
    !hasExplicitDraftVisual
  ) {
    return true;
  }

  if (hasExplicitDraftVisual || segment.videoAction !== "original" || item.source !== "live") {
    return false;
  }

  return doesWorkspaceGeneratedMediaLibraryItemMatchSegmentVisual(segment, item);
};

export const buildWorkspaceGeneratedMediaLibraryEntriesFromMediaLibraryItems = (
  items: WorkspaceMediaLibraryItem[],
): WorkspaceGeneratedMediaLibraryEntry[] =>
  items
    .filter(
      (item) =>
        item.source === "persisted" &&
        (item.kind === "ai_video" || item.kind === "photo_animation" || item.kind === "talking_photo"),
    )
    .map((item) => ({
      createdAt: item.createdAt,
      id: item.itemKey,
      item,
      sourceJobId: item.itemKey,
    }));

export const hydrateWorkspaceSegmentEditorDraftFromGeneratedMediaLibrary = (
  draft: WorkspaceSegmentEditorDraftSession | null | undefined,
  generatedEntries: WorkspaceGeneratedMediaLibraryEntry[],
): WorkspaceSegmentEditorDraftSession | null => {
  if (!draft) {
    return null;
  }

  if (!generatedEntries.length) {
    return draft;
  }

  const latestItemsByRestoreKey = new Map<string, WorkspaceMediaLibraryItem>();
  generatedEntries
    .slice()
    .sort((left, right) => right.createdAt - left.createdAt)
    .forEach((entry) => {
      const projectId = Number(entry.item.projectId);
      const segmentIndex = Number(entry.item.segmentIndex);
      if (!Number.isInteger(projectId) || projectId <= 0 || !Number.isInteger(segmentIndex) || segmentIndex < 0) {
        return;
      }

      const restoreKey = getWorkspaceGeneratedMediaLibraryRestoreKey(projectId, segmentIndex, entry.item.kind);
      if (!latestItemsByRestoreKey.has(restoreKey)) {
        latestItemsByRestoreKey.set(restoreKey, entry.item);
      }
    });

  let hasChanges = false;
  const nextSegments = draft.segments.map((segment) => {
    let nextSegment = segment;

    const applyPatch = (patch: Partial<WorkspaceSegmentEditorDraftSegment>) => {
      hasChanges = true;
      nextSegment = {
        ...nextSegment,
        ...patch,
      };
    };

    const resolveItem = (kind: WorkspaceMediaLibraryItemKind) =>
      latestItemsByRestoreKey.get(getWorkspaceGeneratedMediaLibraryRestoreKey(draft.projectId, segment.index, kind)) ?? null;

    const applyGeneratedVisualAsset = (
      item: WorkspaceMediaLibraryItem,
      currentAsset: StudioCustomVideoFile | null,
      patch: (asset: StudioCustomVideoFile) => Partial<WorkspaceSegmentEditorDraftSegment>,
    ) => {
      if (!item) {
        return false;
      }

      const nextAsset = createStudioCustomVideoFileFromMediaLibraryItem(item);
      if (areStudioCustomVideoFilesSameIdentity(currentAsset, nextAsset)) {
        return true;
      }

      applyPatch(patch(nextAsset));
      return true;
    };

    const aiVideoItem = resolveItem("ai_video");
    if (
      aiVideoItem &&
      shouldHydrateWorkspaceGeneratedMediaLibraryItem(nextSegment, aiVideoItem, {
        allowExplicitDraftVisual: true,
        aiVideoMode: "ai_video",
        videoAction: "ai",
      })
    ) {
      applyGeneratedVisualAsset(aiVideoItem, nextSegment.aiVideoAsset, (asset) => ({
        aiVideoAsset: asset,
        aiVideoGeneratedMode: "ai_video",
        durationExtensionSourceDurationSeconds: null,
        visualReset: false,
        videoAction: "ai",
      }));
    } else if (!nextSegment.aiVideoAsset) {
      const photoAnimationItem = resolveItem("photo_animation");
      if (
        photoAnimationItem &&
        shouldHydrateWorkspaceGeneratedMediaLibraryItem(nextSegment, photoAnimationItem, {
          aiVideoMode: "photo_animation",
          videoAction: "photo_animation",
        })
      ) {
        applyGeneratedVisualAsset(photoAnimationItem, nextSegment.aiVideoAsset, (asset) => ({
          aiVideoAsset: asset,
          aiVideoGeneratedMode: "photo_animation",
          durationExtensionSourceDurationSeconds: null,
          visualReset: false,
          videoAction: "photo_animation",
        }));
      } else {
        const talkingPhotoItem = resolveItem("talking_photo");
        if (
          talkingPhotoItem &&
          shouldHydrateWorkspaceGeneratedMediaLibraryItem(nextSegment, talkingPhotoItem, {
            allowPersistedGeneratedVideoRecovery: true,
            aiVideoMode: "talking_photo",
            videoAction: "talking_photo",
          })
        ) {
          applyGeneratedVisualAsset(talkingPhotoItem, nextSegment.aiVideoAsset, (asset) => ({
            aiVideoAsset: asset,
            aiVideoGeneratedMode: "talking_photo",
            durationExtensionSourceDurationSeconds: null,
            visualReset: false,
            videoAction: "talking_photo",
          }));
        }
      }
    }

    const aiPhotoItem = resolveItem("ai_photo");
    if (
      aiPhotoItem &&
      shouldHydrateWorkspaceGeneratedMediaLibraryItem(nextSegment, aiPhotoItem, {
        allowExplicitDraftVisual: true,
        videoAction: "ai_photo",
      })
    ) {
      applyGeneratedVisualAsset(aiPhotoItem, nextSegment.aiPhotoAsset, (asset) => ({
        aiPhotoAsset: asset,
        durationExtensionSourceDurationSeconds: null,
        visualReset: false,
        videoAction: "ai_photo",
      }));
    }

    const imageEditItem = resolveItem("image_edit");
    if (
      imageEditItem &&
      shouldHydrateWorkspaceGeneratedMediaLibraryItem(nextSegment, imageEditItem, {
        allowExplicitDraftVisual: true,
        videoAction: "image_edit",
      })
    ) {
      applyGeneratedVisualAsset(imageEditItem, nextSegment.imageEditAsset, (asset) => ({
        imageEditAsset: asset,
        durationExtensionSourceDurationSeconds: null,
        visualReset: false,
        videoAction: "image_edit",
      }));
    }

    return nextSegment;
  });

  return hasChanges
    ? {
        ...draft,
        segments: nextSegments,
      }
    : draft;
};

const getStudioPreviewDismissKey = (
  generation: Pick<StudioGeneration, "adId" | "id" | "videoUrl"> | null | undefined,
) => {
  const normalizedId = String(generation?.id ?? "").trim();
  if (normalizedId) {
    return `id:${normalizedId}`;
  }

  if (typeof generation?.adId === "number" && generation.adId > 0) {
    return `ad:${generation.adId}`;
  }

  const normalizedVideoUrl = String(generation?.videoUrl ?? "").trim();
  return normalizedVideoUrl ? `url:${normalizedVideoUrl}` : null;
};

const readDismissedStudioPreviewKey = (email: string | null | undefined) => {
  if (typeof window === "undefined") {
    return null;
  }

  const normalizedEmail = normalizeWorkspaceEmail(email);
  if (!normalizedEmail) {
    return null;
  }

  try {
    const storageValue = window.sessionStorage.getItem(getStudioPreviewDismissStorageKey(normalizedEmail));
    return String(storageValue ?? "").trim() || null;
  } catch {
    return null;
  }
};

const persistDismissedStudioPreviewKey = (email: string | null | undefined, dismissKey: string | null) => {
  if (typeof window === "undefined") {
    return;
  }

  const normalizedEmail = normalizeWorkspaceEmail(email);
  if (!normalizedEmail) {
    return;
  }

  try {
    const storageKey = getStudioPreviewDismissStorageKey(normalizedEmail);
    const normalizedDismissKey = String(dismissKey ?? "").trim();

    if (!normalizedDismissKey) {
      window.sessionStorage.removeItem(storageKey);
      return;
    }

    window.sessionStorage.setItem(storageKey, normalizedDismissKey);
  } catch {
    // Ignore storage write errors.
  }
};

const readHiddenMediaLibraryItemKeys = (email: string | null | undefined) => {
  if (typeof window === "undefined") {
    return [] as string[];
  }

  const normalizedEmail = normalizeWorkspaceEmail(email);
  if (!normalizedEmail) {
    return [] as string[];
  }

  try {
    const storageValue = window.localStorage.getItem(getStudioMediaLibraryHiddenStorageKey(normalizedEmail));
    if (!storageValue) {
      return [] as string[];
    }

    const parsed = JSON.parse(storageValue) as unknown;
    if (!Array.isArray(parsed)) {
      return [] as string[];
    }

    return Array.from(
      new Set(
        parsed
          .map((value) => String(value ?? "").trim())
          .filter((value) => Boolean(value)),
      ),
    );
  } catch {
    return [] as string[];
  }
};

const getDefaultStudioContentPlanVisibility = () => {
  if (typeof window === "undefined" || typeof window.matchMedia !== "function") {
    return true;
  }

  return !window.matchMedia("(max-width: 1100px)").matches;
};

const readStudioContentPlanVisibility = (email: string | null | undefined) => {
  if (typeof window === "undefined") {
    return true;
  }

  const normalizedEmail = normalizeWorkspaceEmail(email);
  if (!normalizedEmail) {
    return getDefaultStudioContentPlanVisibility();
  }

  try {
    const storageValue = window.localStorage.getItem(getStudioContentPlanVisibilityStorageKey(normalizedEmail));
    if (storageValue === "1" || storageValue === "true") {
      return true;
    }

    if (storageValue === "0" || storageValue === "false") {
      return false;
    }
  } catch {
    return getDefaultStudioContentPlanVisibility();
  }

  return getDefaultStudioContentPlanVisibility();
};

const persistStudioContentPlanVisibility = (email: string | null | undefined, isVisible: boolean) => {
  if (typeof window === "undefined") {
    return;
  }

  const normalizedEmail = normalizeWorkspaceEmail(email);
  if (!normalizedEmail) {
    return;
  }

  try {
    window.localStorage.setItem(getStudioContentPlanVisibilityStorageKey(normalizedEmail), isVisible ? "1" : "0");
  } catch {
    // Ignore storage write errors.
  }
};

const persistHiddenMediaLibraryItemKeys = (email: string | null | undefined, keys: string[]) => {
  if (typeof window === "undefined") {
    return;
  }

  const normalizedEmail = normalizeWorkspaceEmail(email);
  if (!normalizedEmail) {
    return;
  }

  try {
    const storageKey = getStudioMediaLibraryHiddenStorageKey(normalizedEmail);
    const normalizedKeys = Array.from(
      new Set(
        keys
          .map((value) => String(value ?? "").trim())
          .filter((value) => Boolean(value)),
      ),
    );

    if (normalizedKeys.length === 0) {
      window.localStorage.removeItem(storageKey);
      return;
    }

    window.localStorage.setItem(storageKey, JSON.stringify(normalizedKeys));
  } catch {
    // Ignore storage write errors.
  }
};

const WORKSPACE_GENERATED_MEDIA_LIBRARY_STORAGE_KEY_PREFIX = "adshorts.generated-media-library:";
const WORKSPACE_GENERATED_MEDIA_LIBRARY_MAX_ENTRIES = 80;

const getWorkspaceGeneratedMediaLibraryStorageKey = (email: string) =>
  `${WORKSPACE_GENERATED_MEDIA_LIBRARY_STORAGE_KEY_PREFIX}${email}`;

const isWorkspaceMediaLibraryPreviewKind = (value: unknown): value is WorkspaceMediaLibraryPreviewKind =>
  value === "image" || value === "video";

const isWorkspaceMediaLibraryItemSource = (value: unknown): value is WorkspaceMediaLibraryItemSource =>
  value === "draft" || value === "live" || value === "persisted";

const isStoredWorkspaceGeneratedMediaLibraryEntry = (value: unknown): value is StoredWorkspaceGeneratedMediaLibraryEntry => {
  if (!value || typeof value !== "object") {
    return false;
  }

  const payload = value as Partial<StoredWorkspaceGeneratedMediaLibraryEntry>;
  const item = payload.item as Partial<WorkspaceMediaLibraryItem> | undefined;

  return (
    Number.isFinite(Number(payload.createdAt)) &&
    typeof payload.id === "string" &&
    typeof payload.sourceJobId === "string" &&
    Boolean(item) &&
    typeof item?.itemKey === "string" &&
    typeof item?.dedupeKey === "string" &&
    typeof item?.downloadName === "string" &&
    (typeof item?.downloadUrl === "string" || item?.downloadUrl === null) &&
    (item?.kind === "ai_photo" ||
      item?.kind === "ai_video" ||
      item?.kind === "photo_animation" ||
      item?.kind === "talking_photo" ||
      item?.kind === "image_edit") &&
    isWorkspaceMediaLibraryPreviewKind(item?.previewKind) &&
    (typeof item?.previewPosterUrl === "string" || item?.previewPosterUrl === null) &&
    typeof item?.previewUrl === "string" &&
    (typeof item?.createdAt === "number" || typeof item?.createdAt === "string" || typeof item?.createdAt === "undefined") &&
    Number.isFinite(Number(item?.projectId)) &&
    typeof item?.projectTitle === "string" &&
    Number.isFinite(Number(item?.segmentIndex)) &&
    Number.isFinite(Number(item?.segmentListIndex)) &&
    Number.isFinite(Number(item?.segmentNumber)) &&
    isWorkspaceMediaLibraryItemSource(item?.source)
  );
};

const normalizeStoredWorkspaceGeneratedMediaLibraryEntry = (
  entry: StoredWorkspaceGeneratedMediaLibraryEntry,
): WorkspaceGeneratedMediaLibraryEntry => {
  const assetId =
    Number.isFinite(Number(entry.item.assetId)) && Number(entry.item.assetId) > 0
      ? Math.trunc(Number(entry.item.assetId))
      : null;
  const previewUrl = assetId
    ? entry.item.previewKind === "video"
      ? buildWorkspaceMediaAssetPlaybackUrl(assetId)
      : buildWorkspaceMediaAssetProxyUrl(assetId)
    : entry.item.previewUrl;
  const downloadUrl = assetId ? buildWorkspaceMediaAssetProxyUrl(assetId) : entry.item.downloadUrl ?? null;

  return {
    createdAt: Math.max(0, Number(entry.createdAt) || 0),
    id: String(entry.id),
    item: {
      ...entry.item,
      assetId,
      createdAt: normalizeWorkspaceMediaLibraryCreatedAt(entry.item.createdAt ?? entry.createdAt),
      downloadUrl,
      previewPosterUrl: entry.item.previewPosterUrl ?? null,
      previewUrl,
    },
    sourceJobId: String(entry.sourceJobId),
  };
};

const readStoredGeneratedMediaLibraryEntries = (
  email: string | null | undefined,
): WorkspaceGeneratedMediaLibraryEntry[] => {
  if (typeof window === "undefined") {
    return [];
  }

  const normalizedEmail = normalizeWorkspaceEmail(email);
  if (!normalizedEmail) {
    return [];
  }

  try {
    const rawValue = window.localStorage.getItem(getWorkspaceGeneratedMediaLibraryStorageKey(normalizedEmail));
    if (!rawValue) {
      return [];
    }

    const parsed = JSON.parse(rawValue) as unknown;
    if (!Array.isArray(parsed)) {
      return [];
    }

    return parsed
      .filter(isStoredWorkspaceGeneratedMediaLibraryEntry)
      .map((entry) => normalizeStoredWorkspaceGeneratedMediaLibraryEntry(entry))
      .sort((left, right) => right.createdAt - left.createdAt)
      .slice(0, WORKSPACE_GENERATED_MEDIA_LIBRARY_MAX_ENTRIES);
  } catch {
    return [];
  }
};

const persistGeneratedMediaLibraryEntries = (
  email: string | null | undefined,
  entries: WorkspaceGeneratedMediaLibraryEntry[],
) => {
  if (typeof window === "undefined") {
    return;
  }

  const normalizedEmail = normalizeWorkspaceEmail(email);
  if (!normalizedEmail) {
    return;
  }

  try {
    const storageKey = getWorkspaceGeneratedMediaLibraryStorageKey(normalizedEmail);
    const normalizedEntries = entries
      .slice()
      .sort((left, right) => right.createdAt - left.createdAt)
      .slice(0, WORKSPACE_GENERATED_MEDIA_LIBRARY_MAX_ENTRIES)
      .map((entry) => normalizeStoredWorkspaceGeneratedMediaLibraryEntry(entry));

    if (normalizedEntries.length === 0) {
      window.localStorage.removeItem(storageKey);
      return;
    }

    window.localStorage.setItem(storageKey, JSON.stringify(normalizedEntries));
  } catch {
    // Ignore storage write errors.
  }
};

const applyWorkspaceContentPlanIdeaUpdate = (
  plans: WorkspaceContentPlan[],
  payload: WorkspaceContentPlanIdeaMutation,
) =>
  plans.map((plan) =>
    plan.id === payload.planId
      ? {
          ...plan,
          ideas: plan.ideas.map((idea) =>
            idea.id === payload.ideaId
              ? {
                  ...idea,
                  isUsed: payload.isUsed,
                  updatedAt: payload.ideaUpdatedAt,
                  usedAt: payload.usedAt,
                }
              : idea,
          ),
          updatedAt: payload.planUpdatedAt,
        }
      : plan,
  );

const removeWorkspaceContentPlanIdea = (
  plans: WorkspaceContentPlan[],
  payload: {
    ideaId: string;
    planId: string;
    updatedAt: string;
  },
) =>
  plans.map((plan) =>
    plan.id !== payload.planId
      ? plan
      : {
          ...plan,
          ideas: plan.ideas.filter((idea) => idea.id !== payload.ideaId),
          updatedAt: payload.updatedAt,
        },
  );

